import type { CareerQuestion } from "./rrt-questions";

export const himQuestions: CareerQuestion[] = [
  { id: "him-001", stem: "A patient is diagnosed with type 2 diabetes mellitus with diabetic chronic kidney disease, stage 3. What is the correct ICD-10-CM coding sequence?", options: ["E11.22, N18.3","N18.3, E11.22","E13.22, N18.3","E11.65, N18.9"], correctIndex: 0, rationale: "ICD-10-CM requires coding the diabetes with the specific manifestation first (E11.22), followed by the CKD stage (N18.3). Sequencing etiology before manifestation is mandatory.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Diabetes Coding" },
  { id: "him-002", stem: "When coding a displaced fracture of the surgical neck of the right humerus, initial encounter, what ICD-10-CM code applies?", options: ["S42.211A","S42.201A","S42.211D","S42.221A"], correctIndex: 0, rationale: "S42.211A captures displaced fracture of the surgical neck of the right humerus, initial encounter. The 7th character 'A' denotes initial encounter.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Fracture Coding" },
  { id: "him-003", stem: "A patient presents with acute exacerbation of chronic obstructive bronchitis. What is the correct ICD-10-CM code?", options: ["J44.1","J44.0","J44.9","J42"], correctIndex: 0, rationale: "J44.1 is correct for COPD with acute exacerbation. J44.0 is for COPD with acute lower respiratory infection.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Respiratory Coding" },
  { id: "him-004", stem: "In ICD-10-PCS, what does the 4th character in a medical/surgical code represent?", options: ["Body part","Root operation","Approach","Device"], correctIndex: 0, rationale: "The 4th character identifies the body part. Structure: Section(1), Body System(2), Root Operation(3), Body Part(4), Approach(5), Device(6), Qualifier(7).", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "PCS Code Structure" },
  { id: "him-005", stem: "Which root operation is defined as cutting out or off, without replacement, a portion of a body part?", options: ["Excision","Resection","Extraction","Detachment"], correctIndex: 0, rationale: "Excision (B) cuts out a portion. Resection cuts out ALL. Extraction pulls/strips. Detachment cuts off extremities.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "PCS Root Operations" },
  { id: "him-006", stem: "A patient has both acute systolic and chronic diastolic heart failure. How should this be coded?", options: ["I50.41","I50.20 and I50.31 separately","I50.9","I50.21 only"], correctIndex: 0, rationale: "ICD-10-CM provides combination codes in I50.4 for combined systolic and diastolic heart failure. I50.41 captures acute combined.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Heart Failure Coding" },
  { id: "him-007", stem: "What is the correct approach value in ICD-10-PCS for a laparoscopic cholecystectomy?", options: ["Percutaneous endoscopic (4)","Open (0)","Percutaneous (3)","Via natural opening endoscopic (8)"], correctIndex: 0, rationale: "Laparoscopic = percutaneous endoscopic approach, value 4. Entry through skin via puncture with endoscope visualization.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "PCS Approaches" },
  { id: "him-008", stem: "When sequencing codes for chemotherapy admission for sigmoid colon cancer, which code is listed first?", options: ["Z51.11 (Encounter for antineoplastic chemotherapy)","C18.7 (Malignant neoplasm of sigmoid colon)","Z85.038 (History of colon malignancy)","C80.1 (Unspecified malignancy)"], correctIndex: 0, rationale: "Per guidelines, when the encounter is solely for chemotherapy, Z51.11 is sequenced first, followed by the neoplasm code.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Neoplasm Coding" },
  { id: "him-009", stem: "A coder encounters 'rule out pneumonia' for an outpatient. What should be coded?", options: ["Signs and symptoms that prompted evaluation","J18.9 (Pneumonia, unspecified)","Z03.89 (Observation for suspected conditions)","Z87.01 (History of pneumonia)"], correctIndex: 0, rationale: "In outpatient coding, 'rule out' diagnoses are NOT coded as confirmed. Code the presenting signs/symptoms instead.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Outpatient Coding Guidelines" },
  { id: "him-010", stem: "What is the ICD-10-CM code for a pressure ulcer of the right heel, stage 3?", options: ["L89.613","L89.611","L89.614","L89.619"], correctIndex: 0, rationale: "L89.613 captures right heel pressure ulcer, stage 3. The 5th character (6) indicates heel, 6th character (3) indicates stage 3.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Pressure Ulcer Coding" },
  { id: "him-011", stem: "Which coding convention indicates mandatory dual coding with specific sequencing?", options: ["Code first / Use additional code pair","Excludes1","Includes note","NEC designation"], correctIndex: 0, rationale: "The 'Code first' and 'Use additional code' convention mandates dual coding with the etiology code sequenced before the manifestation.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Coding Conventions" },
  { id: "him-012", stem: "What root operation applies to a total knee replacement with synthetic substitute?", options: ["Replacement","Revision","Supplement","Change"], correctIndex: 0, rationale: "Replacement (R) puts in material that takes the place of all or portion of a body part. TKR replaces the joint.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "PCS Root Operations" },
  { id: "him-013", stem: "A patient is admitted for sepsis due to MRSA. What is the correct coding?", options: ["A41.02 (Sepsis due to MRSA) with B95.62 for MRSA","A41.9 (Sepsis, unspecified)","A49.02 (MRSA infection, unspecified site)","R65.20 (Severe sepsis without organ dysfunction)"], correctIndex: 0, rationale: "A41.02 specifically codes sepsis due to MRSA. Additional code B95.62 identifies the MRSA organism per coding guidelines.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Infectious Disease Coding" },
  { id: "him-014", stem: "An Excludes1 note in ICD-10-CM means:", options: ["The two conditions cannot occur together; both codes should not be used","The condition is included in the code","Use an additional code","The codes may be used together if both conditions exist"], correctIndex: 0, rationale: "Excludes1 means 'NOT CODED HERE' - the two conditions are mutually exclusive and cannot be reported together. Excludes2 allows both codes.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Coding Conventions" },
  { id: "him-015", stem: "What is the correct way to code a patient with HIV disease and Kaposi's sarcoma?", options: ["B20 (HIV disease) followed by C46.- (Kaposi's sarcoma)","C46.- only","B20 only","Z21 (Asymptomatic HIV status)"], correctIndex: 0, rationale: "HIV disease with a related condition requires B20 first, followed by the manifestation code. Kaposi's sarcoma is an AIDS-defining illness.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "HIV Coding" },
  { id: "him-016", stem: "In ICD-10-PCS, which root operation involves putting in a nonbiological appliance that monitors, assists, performs, or prevents a physiological function?", options: ["Insertion","Replacement","Supplement","Change"], correctIndex: 0, rationale: "Insertion puts in a device that monitors, assists, performs, or prevents a function but does not take the place of a body part (e.g., pacemaker insertion).", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "PCS Root Operations" },
  { id: "him-017", stem: "A patient is seen for a BMI of 42.5 with morbid obesity. Which codes should be reported?", options: ["E66.01 (Morbid obesity due to excess calories) and Z68.42 (BMI 42.0-42.9)","Z68.42 only","E66.9 (Obesity, unspecified) only","E66.01 only"], correctIndex: 0, rationale: "Morbid obesity requires E66.01, and the BMI should be reported as an additional code (Z68.42) per coding guidelines. BMI codes alone should not be used as principal diagnosis.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Obesity Coding" },
  { id: "him-018", stem: "What is the difference between 'initial encounter' and 'subsequent encounter' 7th character extensions?", options: ["Initial = active treatment phase; subsequent = routine care during healing","Initial = first visit only; subsequent = all follow-up visits","Initial = emergency; subsequent = scheduled","Initial = inpatient; subsequent = outpatient"], correctIndex: 0, rationale: "Initial encounter (A) covers the entire period of active treatment, not just the first visit. Subsequent encounter (D) is for routine care during the healing/recovery phase.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Extension Characters" },
  { id: "him-019", stem: "A coder identifies that a patient has both acute and chronic conditions of the same organ. How should these be coded under ICD-10-CM?", options: ["Code both the acute and chronic conditions separately unless a combination code exists","Code only the acute condition","Code only the chronic condition","Code only the combination code Z99"], correctIndex: 0, rationale: "If no combination code exists, code both the acute and chronic conditions separately. ICD-10-CM guidelines direct coding both when documented.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "General Coding Guidelines" },
  { id: "him-020", stem: "What is the correct ICD-10-PCS root operation for a diagnostic arthroscopy of the knee?", options: ["Inspection","Excision","Drainage","Repair"], correctIndex: 0, rationale: "Inspection is the root operation for diagnostic endoscopic procedures where the purpose is visual examination. Diagnostic arthroscopy = Inspection.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "PCS Root Operations" },
  { id: "him-021", stem: "A patient is diagnosed with malignant neoplasm of the upper outer quadrant of the right breast. What is the ICD-10-CM code?", options: ["C50.411","C50.911","C50.412","D05.11"], correctIndex: 0, rationale: "C50.411 specifies malignant neoplasm of the upper-outer quadrant of the right female breast. Site specificity and laterality are required.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Neoplasm Coding" },
  { id: "him-022", stem: "When a patient has a condition that is both a complication of pregnancy and a pre-existing condition, how is it coded?", options: ["Use a code from Chapter 15 (Pregnancy) that identifies the condition as complicating pregnancy","Code the pre-existing condition only","Code pregnancy supervision only","Use two separate codes from different chapters"], correctIndex: 0, rationale: "Chapter 15 codes take priority when conditions complicate pregnancy. These codes indicate the condition is affecting or being affected by the pregnancy.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Obstetric Coding" },
  { id: "him-023", stem: "What does NOS (Not Otherwise Specified) mean in ICD-10-CM?", options: ["The documentation does not provide enough detail to assign a more specific code","The condition has no specific code in the classification","The provider must be queried","The condition is rare and unlisted"], correctIndex: 0, rationale: "NOS indicates the information in the medical record is insufficient to assign a more specific code. It is equivalent to 'unspecified.' The coder should query when possible.", difficulty: 1, category: "ICD-10-CM/PCS Coding", topic: "Coding Conventions" },
  { id: "him-024", stem: "A surgeon performs a total abdominal hysterectomy with bilateral salpingo-oophorectomy. Which CPT code range applies?", options: ["58150-58294 (Hysterectomy procedures)","58600-58770 (Oviduct/Ovary procedures)","58400-58540 (Uterus manipulation)","59000-59899 (Maternity care)"], correctIndex: 0, rationale: "Total abdominal hysterectomy falls within CPT 58150-58294. CPT 58150 covers TAH with or without removal of tubes/ovaries.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "Surgical Coding" },
  { id: "him-025", stem: "What does modifier -25 indicate on an E/M code?", options: ["Significant, separately identifiable E/M service on same day as a procedure","Professional component only","Bilateral procedure","Reduced services"], correctIndex: 0, rationale: "Modifier -25 indicates a significant, separately identifiable E/M service by the same physician on the same day as another procedure.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "CPT Modifiers" },
  { id: "him-026", stem: "HCPCS Level II codes beginning with 'J' typically represent:", options: ["Drugs administered by injection","Durable medical equipment","Pathology and laboratory services","Temporary codes"], correctIndex: 0, rationale: "HCPCS J-codes represent drugs administered other than oral method — primarily injectable drugs.", difficulty: 1, category: "CPT/HCPCS Coding", topic: "HCPCS Coding" },
  { id: "him-027", stem: "When a bilateral procedure has indicator '1' in MPFS, which modifier is appended?", options: ["Modifier -50 (Bilateral procedure)","Modifier -59 (Distinct procedural service)","Modifier -51 (Multiple procedures)","Modifier -22 (Increased procedural service)"], correctIndex: 0, rationale: "Modifier -50 indicates a bilateral procedure. Indicator '1' means it's subject to bilateral surgery adjustments at 150% payment.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "CPT Modifiers" },
  { id: "him-028", stem: "Which CPT category includes codes for emerging technologies?", options: ["Category III","Category I","Category II","Unlisted codes"], correctIndex: 0, rationale: "Category III codes are temporary codes for emerging technology. They use alphanumeric codes ending in 'T'.", difficulty: 1, category: "CPT/HCPCS Coding", topic: "CPT Structure" },
  { id: "him-029", stem: "A patient receives 95 minutes of critical care. How is this coded?", options: ["99291 x1, 99292 x1","99291 x1","99291 x2","99292 x3"], correctIndex: 0, rationale: "99291 covers first 30-74 minutes. 99292 covers each additional 30 min. For 95 min: 99291 + 99292 x1.", difficulty: 3, category: "CPT/HCPCS Coding", topic: "Critical Care Coding" },
  { id: "him-030", stem: "What is the correct use of modifier -26?", options: ["Professional component of a procedure only","Repeat procedure","Technical component only","Staged procedure"], correctIndex: 0, rationale: "Modifier -26 reports only the professional component when the physician interprets but doesn't own the equipment.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "CPT Modifiers" },
  { id: "him-031", stem: "An established patient office visit with moderate MDM uses which code?", options: ["99214","99213","99215","99203"], correctIndex: 0, rationale: "For established patients, moderate MDM = 99214. Code selection based on MDM or total time. 99203 is for new patients.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "E/M Coding" },
  { id: "him-032", stem: "Immunization codes are found in which CPT section?", options: ["Medicine section (90000 series)","Surgery section","Evaluation and Management","Pathology and Laboratory"], correctIndex: 0, rationale: "Immunization codes (90460-90474 administration, 90476-90756 products) are in the Medicine section.", difficulty: 1, category: "CPT/HCPCS Coding", topic: "CPT Structure" },
  { id: "him-033", stem: "A procedure not described by any CPT code should use:", options: ["An unlisted procedure code from the appropriate subsection","Closest matching CPT code with modifier -22","A Category III code","No code — narrative only"], correctIndex: 0, rationale: "When no CPT code describes the procedure, use an unlisted code from the appropriate subsection with a special report.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "Unlisted Procedures" },
  { id: "him-034", stem: "The global surgical package includes:", options: ["Preoperative visits after decision, intraoperative services, and postoperative follow-up within the global period","Only the surgical procedure itself","Preoperative visits, procedure, and 1 year of follow-up","Procedure and all related lab tests"], correctIndex: 0, rationale: "The global package includes: pre-op visits after surgery decision, intraoperative services, and routine post-op follow-up within the designated global period (0, 10, or 90 days).", difficulty: 2, category: "CPT/HCPCS Coding", topic: "Global Period" },
  { id: "him-035", stem: "What is modifier -59 used for?", options: ["Indicating a distinct procedural service that is separate from other services on the same date","Bilateral procedures","Repeat procedures by the same physician","Professional component"], correctIndex: 0, rationale: "Modifier -59 identifies procedures/services that are separate and distinct from other services on the same date. It overrides NCCI bundling edits.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "CPT Modifiers" },
  { id: "him-036", stem: "When coding multiple surgical procedures performed during the same session, which modifier is applied to the secondary procedures?", options: ["Modifier -51 (Multiple procedures)","Modifier -59 (Distinct procedural service)","Modifier -50 (Bilateral procedure)","Modifier -62 (Two surgeons)"], correctIndex: 0, rationale: "Modifier -51 is appended to secondary procedures when multiple procedures are performed in the same session. The primary procedure is listed first without -51.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "CPT Modifiers" },
  { id: "him-037", stem: "What is an add-on code in CPT?", options: ["A code that must be reported in conjunction with a primary procedure code, never standalone","A code that replaces an existing code","A supplementary billing code for supplies","A code that increases the payment for a procedure"], correctIndex: 0, rationale: "Add-on codes (identified with + symbol) are always performed in addition to a primary procedure and cannot be reported as standalone services. They are exempt from modifier -51.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "Add-On Codes" },
  { id: "him-038", stem: "Which E/M code would be used for an initial observation care encounter with high MDM complexity?", options: ["99223","99222","99221","99236"], correctIndex: 0, rationale: "99223 is for initial observation care with high MDM complexity. 99221-99223 represent low, moderate, and high complexity respectively.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "E/M Coding" },
  { id: "him-039", stem: "A radiologist interprets a chest X-ray (2 views). The appropriate CPT code is:", options: ["71046","71045","71047","71048"], correctIndex: 0, rationale: "71046 is the CPT code for chest X-ray, 2 views (frontal and lateral). 71045 is single view, 71047 is 3 views, 71048 is 4+ views.", difficulty: 1, category: "CPT/HCPCS Coding", topic: "Radiology Coding" },
  { id: "him-040", stem: "What does the CPT term 'separate procedure' mean?", options: ["The procedure is commonly part of a larger procedure but can be coded independently when performed alone or for a distinctly separate purpose","The procedure must always be coded separately","The procedure requires a separate operating room","The procedure is performed by a different surgeon"], correctIndex: 0, rationale: "A 'separate procedure' designation means the procedure is usually integral to a larger service but may be reported independently when performed alone or for a distinct indication.", difficulty: 3, category: "CPT/HCPCS Coding", topic: "CPT Conventions" },
  { id: "him-041", stem: "Which modifier indicates that a procedure was performed in an ASC (Ambulatory Surgical Center)?", options: ["Modifier -SG or facility-specific HCPCS modifiers","Modifier -25","Modifier -51","Modifier -26"], correctIndex: 0, rationale: "ASC-related modifiers include HCPCS modifiers for facility reporting. The specific modifier depends on payer requirements. CMS uses facility POS codes and specific ASC payment indicators.", difficulty: 3, category: "CPT/HCPCS Coding", topic: "Facility Coding" },
  { id: "him-042", stem: "When coding for anesthesia services, time is reported in:", options: ["Actual minutes from start of anesthesia to when the patient may be safely placed under post-anesthesia supervision","15-minute increments","1-hour blocks","Total OR time including setup"], correctIndex: 0, rationale: "Anesthesia time begins when the anesthesiologist begins to prepare the patient and ends when the patient can be safely transferred to post-anesthesia care.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "Anesthesia Coding" },
  { id: "him-043", stem: "What CPT code section covers pathology consultations during surgery (frozen sections)?", options: ["88329-88334 (Pathology consultations during surgery)","80047-80081 (Organ panels)","88300-88309 (Surgical pathology)","88321-88325 (Consultations and referrals)"], correctIndex: 0, rationale: "Frozen section pathology consultations during surgery are coded with 88329-88334. These cover intraoperative pathology consultation requiring examination of tissue.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "Pathology Coding" },
  { id: "him-044", stem: "Under HIPAA, which is NOT considered PHI?", options: ["De-identified data meeting Safe Harbor criteria","A patient's name linked to diagnosis","Medical record numbers","Health insurance beneficiary numbers"], correctIndex: 0, rationale: "De-identified data meeting Safe Harbor (removal of 18 identifiers) or Expert Determination is NOT PHI.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "PHI Definition" },
  { id: "him-045", stem: "What is the maximum civil penalty per violation for Tier 1 HIPAA violations?", options: ["$100-$50,000 per violation","$1,000-$50,000","$10,000-$50,000","$50,000 per violation"], correctIndex: 0, rationale: "Tier 1 (did not know): $100-$50,000. Tier 2 (reasonable cause): $1,000-$50,000. Tier 3 (willful neglect, corrected): $10,000-$50,000.", difficulty: 3, category: "HIPAA Privacy & Security", topic: "HIPAA Penalties" },
  { id: "him-046", stem: "The HIPAA Security Rule requires which three categories of safeguards?", options: ["Administrative, physical, and technical","Administrative, operational, and technical","Physical, technical, and procedural","Administrative, physical, and organizational"], correctIndex: 0, rationale: "Three safeguard categories: Administrative (policies, training), Physical (facility access), Technical (access controls, encryption, audit).", difficulty: 1, category: "HIPAA Privacy & Security", topic: "Security Rule" },
  { id: "him-047", stem: "Patient's right to access medical records must be fulfilled within:", options: ["30 days, with one 30-day extension permitted","60 days","15 business days","7 calendar days"], correctIndex: 0, rationale: "HIPAA requires providing PHI access within 30 days. A single 30-day extension is permitted with written notice.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Patient Rights" },
  { id: "him-048", stem: "Which HIPAA concept limits PHI access to the minimum needed?", options: ["Minimum necessary standard","Need-to-know principle","Least privilege access","Role-based access control"], correctIndex: 0, rationale: "The minimum necessary standard requires limiting PHI access/use/disclosure to the minimum necessary. Exceptions include treatment and individual requests.", difficulty: 1, category: "HIPAA Privacy & Security", topic: "Privacy Rule" },
  { id: "him-049", stem: "A healthcare worker posts a photo showing a patient wristband. This constitutes:", options: ["A potential HIPAA violation due to identifiable information","Acceptable if patient's face isn't visible","A violation only if the post goes viral","Not a violation because social media is personal"], correctIndex: 0, rationale: "Patient wristbands contain identifiers (name, DOB, MRN) = PHI. Posting images with PHI violates HIPAA regardless of intent.", difficulty: 1, category: "HIPAA Privacy & Security", topic: "Social Media & PHI" },
  { id: "him-050", stem: "Which entity enforces HIPAA regulations?", options: ["OCR within HHS","CMS","Joint Commission","State Department of Health"], correctIndex: 0, rationale: "The Office for Civil Rights (OCR) within HHS enforces HIPAA Privacy and Security Rules, investigates complaints, and imposes penalties.", difficulty: 1, category: "HIPAA Privacy & Security", topic: "HIPAA Enforcement" },
  { id: "him-051", stem: "A BAA is required when:", options: ["A covered entity shares PHI with a vendor performing functions on its behalf","Two providers share PHI for treatment","A patient authorizes release to family","A covered entity reports to public health authority"], correctIndex: 0, rationale: "A Business Associate Agreement is required when sharing PHI with any entity that creates/receives/maintains/transmits PHI on behalf of the covered entity.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Business Associates" },
  { id: "him-052", stem: "Breach notification to individuals must occur within:", options: ["60 days of discovery","30 days","90 days","24 hours"], correctIndex: 0, rationale: "Notification must occur without unreasonable delay, no later than 60 days after discovery. Breaches affecting 500+ also require media and HHS notification.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Breach Notification" },
  { id: "him-053", stem: "Which is an example of a technical safeguard?", options: ["Encryption of ePHI","Employee background checks","Physical access controls to servers","Written privacy policies"], correctIndex: 0, rationale: "Encryption is a technical safeguard. Background checks = administrative. Physical access = physical safeguard. Written policies = administrative.", difficulty: 1, category: "HIPAA Privacy & Security", topic: "Security Safeguards" },
  { id: "him-054", stem: "Under HIPAA, patients have the right to:", options: ["Request amendments to their medical records","Demand deletion of accurate records","Prevent all disclosures for treatment","Access other patients' records"], correctIndex: 0, rationale: "Patients can request amendments to their records. The provider can deny if the information is accurate/complete but must document the request and denial.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Patient Rights" },
  { id: "him-055", stem: "Which of the following disclosures does NOT require patient authorization under HIPAA?", options: ["Treatment, payment, and healthcare operations (TPO)","Marketing purposes","Sale of PHI","Research without IRB waiver"], correctIndex: 0, rationale: "HIPAA permits disclosure without authorization for TPO. Marketing, sale of PHI, and most research uses require written authorization.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Authorization Requirements" },
  { id: "him-056", stem: "An encryption standard recommended for ePHI at rest is:", options: ["AES-256 encryption","Simple password protection","Base64 encoding","ZIP file compression"], correctIndex: 0, rationale: "AES-256 (Advanced Encryption Standard with 256-bit key) is the recommended encryption standard for ePHI. Password protection and encoding alone are insufficient.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Encryption Standards" },
  { id: "him-057", stem: "A HIPAA risk analysis must:", options: ["Assess potential risks and vulnerabilities to ePHI and implement appropriate security measures","Be performed only once during initial system setup","Focus only on external threats","Be conducted by law enforcement"], correctIndex: 0, rationale: "A risk analysis must assess all potential risks/vulnerabilities to ePHI, be conducted regularly, cover all ePHI-containing systems, and lead to risk management measures.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Risk Analysis" },
  { id: "him-058", stem: "The HIPAA Privacy Rule applies to which entities?", options: ["Covered entities (health plans, healthcare clearinghouses, providers who transmit health information electronically) and their business associates","All businesses in the United States","Only hospitals and physician offices","Only health insurance companies"], correctIndex: 0, rationale: "HIPAA applies to covered entities (health plans, clearinghouses, providers conducting electronic transactions) and their business associates.", difficulty: 1, category: "HIPAA Privacy & Security", topic: "HIPAA Scope" },
  { id: "him-059", stem: "Which standard is used for electronic exchange of clinical information between systems?", options: ["HL7 FHIR","DICOM","SNOMED CT","LOINC"], correctIndex: 0, rationale: "HL7 FHIR is the modern standard for healthcare data exchange using RESTful APIs. DICOM = imaging, SNOMED CT = terminology, LOINC = lab observations.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Interoperability Standards" },
  { id: "him-060", stem: "What does 'interoperability' mean in health IT?", options: ["The ability of different systems to exchange and use shared data","Converting paper records to electronic format","Security protocol for patient data","Backup system for EHRs"], correctIndex: 0, rationale: "Interoperability = ability of systems to access, exchange, integrate, and use data. Exists at foundational, structural, semantic, and organizational levels.", difficulty: 1, category: "EHR Systems & Health IT", topic: "Interoperability" },
  { id: "him-061", stem: "Which federal law incentivized EHR adoption through Medicare/Medicaid?", options: ["HITECH Act (ARRA 2009)","Affordable Care Act","HIPAA","21st Century Cures Act"], correctIndex: 0, rationale: "HITECH Act provided financial incentives for meaningful use of certified EHR technology.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Health IT Legislation" },
  { id: "him-062", stem: "A Clinical Decision Support (CDS) system:", options: ["Provides clinicians with knowledge and patient-specific info to enhance decision-making","Calculates billing reimbursement","Is a patient portal for lab results","Schedules appointments"], correctIndex: 0, rationale: "CDS analyzes patient data against clinical knowledge to provide alerts, reminders, diagnostic suggestions, and drug interaction warnings.", difficulty: 1, category: "EHR Systems & Health IT", topic: "Clinical Decision Support" },
  { id: "him-063", stem: "'Information blocking' under the Cures Act means:", options: ["Practices unreasonably limiting availability of electronic health information","Encrypting patient data for security","Restricting EHR access to authorized users","Archiving old medical records"], correctIndex: 0, rationale: "Information blocking = practices likely to interfere with access, exchange, or use of electronic health information, unless meeting specific exceptions.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Information Blocking" },
  { id: "him-064", stem: "SNOMED CT is best described as:", options: ["Comprehensive clinical terminology for encoding concepts in EHRs","A billing classification system","A drug interaction database","A radiology information system"], correctIndex: 0, rationale: "SNOMED CT is the most comprehensive clinical healthcare terminology providing standardized codes for diseases, findings, procedures, and body structures.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Clinical Terminologies" },
  { id: "him-065", stem: "CPOE stands for:", options: ["Computerized Provider Order Entry","Clinical Patient Outcome Evaluation","Certified Professional Order Entry","Computerized Patient Organization Engine"], correctIndex: 0, rationale: "CPOE enables providers to directly enter medical orders into a computer system, reducing handwriting errors and enabling real-time CDS alerts.", difficulty: 1, category: "EHR Systems & Health IT", topic: "EHR Components" },
  { id: "him-066", stem: "LOINC is specifically designed for coding:", options: ["Laboratory test names and clinical observations","Surgical procedures","Diagnoses","Drug names"], correctIndex: 0, rationale: "LOINC provides universal codes for laboratory tests and clinical observations, standardizing test identification across systems.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Clinical Terminologies" },
  { id: "him-067", stem: "What is a patient portal?", options: ["A secure online website giving patients 24-hour access to their health information","A physical entrance to a hospital","A provider's billing dashboard","An internal staff communication tool"], correctIndex: 0, rationale: "A patient portal provides secure online access to personal health data, lab results, appointment scheduling, prescription refills, and provider messaging.", difficulty: 1, category: "EHR Systems & Health IT", topic: "Patient Engagement" },
  { id: "him-068", stem: "RxNorm is a standardized nomenclature for:", options: ["Clinical drugs and drug delivery devices","Radiology procedures","Laboratory tests","Nursing diagnoses"], correctIndex: 0, rationale: "RxNorm provides normalized names for clinical drugs and links to drug vocabularies including NDC, SNOMED CT, and drug interactions databases.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Clinical Terminologies" },
  { id: "him-069", stem: "What is the purpose of audit trails in an EHR system?", options: ["Recording who accessed, modified, or transmitted patient information and when","Tracking patient appointment attendance","Monitoring staff break times","Scheduling system maintenance"], correctIndex: 0, rationale: "Audit trails create a chronological record of EHR access and modifications, supporting HIPAA compliance, security monitoring, and legal requirements.", difficulty: 2, category: "EHR Systems & Health IT", topic: "EHR Security" },
  { id: "him-070", stem: "Meaningful Use (now Promoting Interoperability) measures focus on:", options: ["Using certified EHR technology to improve quality, safety, and efficiency of healthcare","Ensuring all staff can type proficiently","Maximizing the number of data fields in records","Reducing the cost of EHR software"], correctIndex: 0, rationale: "Meaningful Use/Promoting Interoperability measures ensure EHR technology improves healthcare quality, engages patients, improves care coordination, and maintains privacy/security.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Health IT Policy" },
  { id: "him-071", stem: "What is telehealth?", options: ["Delivery of healthcare services remotely using telecommunications technology","Telephone-based appointment scheduling","Hospital paging systems","Remote monitoring of server rooms"], correctIndex: 0, rationale: "Telehealth encompasses remote clinical services (telemedicine), patient monitoring, health education, and health administration via telecommunications technology.", difficulty: 1, category: "EHR Systems & Health IT", topic: "Telehealth" },
  { id: "him-072", stem: "The primary purpose of charge capture is:", options: ["Recording all billable services to generate accurate claims","Collecting patient copayments at check-in","Verifying insurance eligibility","Posting payments to accounts"], correctIndex: 0, rationale: "Charge capture records all billable services to ensure claims reflect actual services delivered, preventing revenue leakage.", difficulty: 1, category: "Revenue Cycle Management", topic: "Charge Capture" },
  { id: "him-073", stem: "Denial management involves:", options: ["Identifying, analyzing, and resolving rejected/denied claims","Denying patient payment plans","Refusing to submit claims to problematic payers","Managing patient billing complaints"], correctIndex: 0, rationale: "Denial management systematically identifies denial reasons, corrects errors, resubmits claims, and implements process improvements.", difficulty: 2, category: "Revenue Cycle Management", topic: "Denial Management" },
  { id: "him-074", stem: "Days in Accounts Receivable measures:", options: ["Average days to collect payment after service","Net collection rate","Clean claim rate","Denial rate"], correctIndex: 0, rationale: "Days in A/R = average time from date of service to payment. Lower = faster collection. Industry benchmark: 30-40 days.", difficulty: 2, category: "Revenue Cycle Management", topic: "Revenue Cycle Metrics" },
  { id: "him-075", stem: "A clean claim is:", options: ["A claim without errors that can be processed without additional development","A claim paid in full","A claim submitted within 24 hours","A claim for preventive services only"], correctIndex: 0, rationale: "A clean claim has all required data, correct format, no deficiencies. Clean claim rates above 95% indicate effective front-end processes.", difficulty: 1, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-076", stem: "Prior authorization is:", options: ["Obtaining payer approval before delivering certain services","Authorizing staff to access financial records","Getting patient treatment consent","Approving physician credentials"], correctIndex: 0, rationale: "Prior authorization obtains advance approval from a health plan before specific services/procedures/medications. Missing it often results in denial.", difficulty: 1, category: "Revenue Cycle Management", topic: "Prior Authorization" },
  { id: "him-077", stem: "A remittance advice (RA) is:", options: ["A payer document explaining claim adjudication, payment, and adjustments","A bill sent to the patient","A referral form","A medical record summary"], correctIndex: 0, rationale: "An RA (or ERA/835) details how each claim was processed: billed amount, allowed amount, adjustments, patient responsibility, payment.", difficulty: 2, category: "Revenue Cycle Management", topic: "Payment Posting" },
  { id: "him-078", stem: "Revenue integrity programs focus on:", options: ["Accurate charge capture, coding compliance, and preventing revenue leakage","Maximizing billing regardless of documentation","Reducing staff wages","Eliminating patient financial assistance"], correctIndex: 0, rationale: "Revenue integrity ensures charges accurately reflect services, coding is compliant, and processes prevent over-billing and under-billing.", difficulty: 2, category: "Revenue Cycle Management", topic: "Revenue Integrity" },
  { id: "him-079", stem: "The chargemaster (CDM) is:", options: ["A comprehensive list of all billable items with associated charges and codes","A master schedule of physician hours","A patient demographics database","An approved medications list"], correctIndex: 0, rationale: "The CDM contains all billable items/services with descriptions, revenue codes, CPT/HCPCS codes, and standard charges. It drives billing.", difficulty: 2, category: "Revenue Cycle Management", topic: "Chargemaster" },
  { id: "him-080", stem: "What is 'eligibility verification' in the revenue cycle?", options: ["Confirming a patient's insurance coverage and benefits before services are provided","Verifying a physician's medical license","Checking if a patient has a will","Confirming a nurse's certification status"], correctIndex: 0, rationale: "Eligibility verification confirms active coverage, benefits, copays, deductibles, and network status before providing services to reduce denials.", difficulty: 1, category: "Revenue Cycle Management", topic: "Front-End Revenue Cycle" },
  { id: "him-081", stem: "What is the 835 electronic transaction?", options: ["Electronic Remittance Advice (ERA) - payer's explanation of payment/adjustment","Eligibility inquiry","Claim submission","Prior authorization request"], correctIndex: 0, rationale: "The ANSI X12 835 transaction is the Electronic Remittance Advice that communicates payment information from payer to provider electronically.", difficulty: 2, category: "Revenue Cycle Management", topic: "EDI Transactions" },
  { id: "him-082", stem: "What is the 837 electronic transaction used for?", options: ["Submitting healthcare claims electronically","Checking patient eligibility","Sending remittance advice","Processing prior authorizations"], correctIndex: 0, rationale: "The 837 transaction (837P for professional, 837I for institutional, 837D for dental) is the standard format for submitting electronic healthcare claims.", difficulty: 2, category: "Revenue Cycle Management", topic: "EDI Transactions" },
  { id: "him-083", stem: "What does 'write-off' mean in revenue cycle?", options: ["Removing uncollectible balances from accounts receivable","Writing patient discharge summaries","Writing prescriptions electronically","Writing off medical equipment as depreciation"], correctIndex: 0, rationale: "Write-offs remove uncollectible amounts from A/R. Types include contractual adjustments, bad debt, charity care, and administrative write-offs.", difficulty: 2, category: "Revenue Cycle Management", topic: "Payment Posting" },
  { id: "him-084", stem: "A patient's financial responsibility typically includes:", options: ["Copayments, coinsurance, deductibles, and non-covered services","The total cost of all medical care regardless of insurance","Only copayments","Nothing if they have insurance"], correctIndex: 0, rationale: "Patient responsibility includes copays, coinsurance (% of allowed amount), unmet deductible, and any services not covered by their plan.", difficulty: 1, category: "Revenue Cycle Management", topic: "Patient Responsibility" },
  { id: "him-085", stem: "Net collection rate is calculated as:", options: ["Payments collected divided by charges minus contractual adjustments","Total charges divided by total payments","Number of claims paid divided by claims submitted","Total revenue divided by total expenses"], correctIndex: 0, rationale: "Net collection rate = payments / (charges - contractual adjustments) × 100. It measures how effectively a practice collects what it's owed. Target: >95%.", difficulty: 3, category: "Revenue Cycle Management", topic: "Revenue Cycle Metrics" },
  { id: "him-086", stem: "The primary goal of a CDI program is:", options: ["Ensuring documentation accurately reflects severity of illness and complexity of care","Reducing medical record pages","Eliminating physician dictation","Increasing number of diagnoses coded"], correctIndex: 0, rationale: "CDI ensures documentation reflects patient severity, risk of mortality, and care complexity for accurate coding, reimbursement, and quality metrics.", difficulty: 1, category: "Clinical Documentation Improvement", topic: "CDI Fundamentals" },
  { id: "him-087", stem: "A CDI specialist finds 'pneumonia' without type/organism specified. What should they do?", options: ["Query the physician for specificity","Code J18.9 without query","Add bacterial pneumonia diagnosis","Ignore the documentation"], correctIndex: 0, rationale: "CDI specialists query for specificity. Unspecified pneumonia (J18.9) has lower severity weighting than organism/type-specific codes.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "CDI Queries" },
  { id: "him-088", stem: "Case Mix Index (CMI) measures:", options: ["Average DRG weight of a facility's cases, reflecting CDI program effectiveness","Patient satisfaction","Length of stay only","Readmission rates"], correctIndex: 0, rationale: "CMI = average DRG weight. CDI efforts to capture accurate severity improve CMI accuracy, impacting reimbursement and resource allocation.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "CDI Metrics" },
  { id: "him-089", stem: "A compliant physician query must be:", options: ["Non-leading, clinically relevant, and based on existing documentation","Leading toward a specific diagnosis for higher reimbursement","Submitted only after discharge","Generated automatically by coding software"], correctIndex: 0, rationale: "Queries must be non-leading, clinically relevant, and based on existing documentation per AHIMA and ACDIS guidelines.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "CDI Queries" },
  { id: "him-090", stem: "Present on Admission (POA) indicators are required for:", options: ["All diagnoses on inpatient Medicare claims","Only the principal diagnosis","Outpatient claims only","Surgical procedures only"], correctIndex: 0, rationale: "POA indicators are required for all diagnoses on inpatient Medicare claims. Values: Y (yes), N (no), W (clinically undetermined), 1 (exempt).", difficulty: 2, category: "Clinical Documentation Improvement", topic: "POA Indicators" },
  { id: "him-091", stem: "More specific documentation leads to:", options: ["More accurate DRG assignment reflecting true resource consumption","No impact on DRG assignment","Always higher-weighted DRGs","Only affects outpatient coding"], correctIndex: 0, rationale: "Specific documentation (e.g., 'acute respiratory failure' vs. 'respiratory distress') directly impacts CC/MCC capture and DRG assignment.", difficulty: 3, category: "Clinical Documentation Improvement", topic: "Documentation Impact" },
  { id: "him-092", stem: "Which is classified as a Major Complication or Comorbidity (MCC)?", options: ["Sepsis","Essential hypertension","Seasonal allergies","Mild anxiety"], correctIndex: 0, rationale: "Sepsis is an MCC, significantly increasing DRG weight. Essential hypertension, allergies, and mild anxiety are not CCs/MCCs.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "CC/MCC Classification" },
  { id: "him-093", stem: "What is the difference between a concurrent and retrospective CDI review?", options: ["Concurrent occurs during admission; retrospective occurs after discharge","Concurrent is after discharge; retrospective is during admission","Both occur at the same time","There is no difference"], correctIndex: 0, rationale: "Concurrent reviews happen while the patient is still admitted, allowing real-time query opportunities. Retrospective reviews occur after discharge, limiting query options.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "CDI Review Types" },
  { id: "him-094", stem: "A CDI specialist identifies acute respiratory failure documented by the physician but not coded. This is an example of:", options: ["Missed CC/MCC opportunity requiring coder education","Normal coding variation","A documentation error","An insignificant finding"], correctIndex: 0, rationale: "Acute respiratory failure is an MCC. If documented but not coded, it represents a missed CC/MCC capture opportunity that CDI should address through coder education.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "CDI Impact" },
  { id: "him-095", stem: "Which documentation element is MOST important for accurate DRG assignment?", options: ["Clinical specificity of principal and secondary diagnoses","Length of the progress notes","Number of orders written","Patient demographics"], correctIndex: 0, rationale: "Clinical specificity of diagnoses drives DRG assignment. The principal diagnosis determines the MDC and base DRG, while secondary diagnoses with CC/MCC status impact final DRG.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "Documentation Specificity" },
  { id: "him-096", stem: "Data governance refers to:", options: ["Overall management of data availability, usability, integrity, and security","Deleting old records","Software for data entry","Hardware infrastructure for storage"], correctIndex: 0, rationale: "Data governance encompasses policies, procedures, standards, and metrics ensuring effective use of information including quality, stewardship, and security.", difficulty: 2, category: "Data Analytics & Quality", topic: "Data Governance" },
  { id: "him-097", stem: "Which measure describes central tendency calculated by sum/count?", options: ["Mean","Median","Mode","Standard deviation"], correctIndex: 0, rationale: "Mean = sum of all values / count. Median = middle value. Mode = most frequent. Standard deviation = data spread.", difficulty: 1, category: "Data Analytics & Quality", topic: "Basic Statistics" },
  { id: "him-098", stem: "The primary purpose of a clinical data warehouse is:", options: ["Integrating data from multiple sources for analysis and decision-making","Replacing the EHR","Storing only financial data","Real-time patient monitoring"], correctIndex: 0, rationale: "Clinical data warehouses aggregate data from EHR, billing, lab, pharmacy for query, analysis, and reporting.", difficulty: 2, category: "Data Analytics & Quality", topic: "Data Warehousing" },
  { id: "him-099", stem: "HEDIS measures are used for:", options: ["Evaluating health plan performance on quality of care","Calculating hospital construction costs","Determining physician salaries","Assigning ICD-10 codes"], correctIndex: 0, rationale: "HEDIS measures by NCQA evaluate health plan performance across more than 90 quality dimensions.", difficulty: 2, category: "Data Analytics & Quality", topic: "Quality Measures" },
  { id: "him-100", stem: "Data integrity means:", options: ["Data is accurate, consistent, and trustworthy throughout its lifecycle","Data is stored in multiple backups","Data is available 24/7","Data is entered by authorized personnel only"], correctIndex: 0, rationale: "Data integrity = accuracy, consistency, and reliability throughout the data lifecycle from creation through retrieval.", difficulty: 1, category: "Data Analytics & Quality", topic: "Data Quality" },
  { id: "him-101", stem: "Which chart displays frequency distribution of a continuous variable?", options: ["Histogram","Pie chart","Scatter plot","Pareto chart"], correctIndex: 0, rationale: "Histograms display frequency distribution with adjacent bars. Pie = proportions. Scatter = relationships. Pareto = significance ranking.", difficulty: 1, category: "Data Analytics & Quality", topic: "Data Visualization" },
  { id: "him-102", stem: "Risk adjustment in healthcare data analysis:", options: ["Accounts for patient severity/demographics differences when comparing outcomes","Adjusts billing based on patient income","Modifies treatment protocols","Calculates insurance premiums"], correctIndex: 0, rationale: "Risk adjustment accounts for population differences (age, severity, comorbidities) to ensure fair outcome comparisons across providers.", difficulty: 3, category: "Data Analytics & Quality", topic: "Risk Adjustment" },
  { id: "him-103", stem: "To identify readmission patterns, which analytics approach is most appropriate?", options: ["Predictive analytics using historical data","Simply counting readmissions per month","Asking physicians for predictions","Reviewing only readmitted patient records"], correctIndex: 0, rationale: "Predictive analytics uses statistical models on historical data to identify patterns and predict high-risk patients for targeted interventions.", difficulty: 3, category: "Data Analytics & Quality", topic: "Predictive Analytics" },
  { id: "him-104", stem: "What does the term 'big data' in healthcare refer to?", options: ["Large, complex datasets from diverse sources requiring advanced analytics tools","Data printed in large font","Physical storage of paper records","Data limited to a single facility"], correctIndex: 0, rationale: "Healthcare big data encompasses massive datasets from EHRs, genomics, claims, IoT devices, and social determinants requiring advanced analytics for insights.", difficulty: 2, category: "Data Analytics & Quality", topic: "Big Data" },
  { id: "him-105", stem: "A run chart is used to:", options: ["Display data over time to identify trends and patterns","Show proportional relationships","Compare two variables","Calculate statistical significance"], correctIndex: 0, rationale: "Run charts display data points over time, making it easy to identify trends, shifts, and patterns in process performance.", difficulty: 2, category: "Data Analytics & Quality", topic: "Quality Improvement Tools" },
  { id: "him-106", stem: "The PDSA cycle stands for:", options: ["Plan-Do-Study-Act","Plan-Document-Survey-Analyze","Prepare-Develop-Submit-Approve","Process-Data-System-Audit"], correctIndex: 0, rationale: "PDSA (Plan-Do-Study-Act) is a quality improvement methodology for testing changes. Plan the test, do it, study results, act on findings.", difficulty: 1, category: "Data Analytics & Quality", topic: "Quality Improvement" },
  { id: "him-107", stem: "What is a balanced scorecard in healthcare?", options: ["A strategic planning framework measuring performance across multiple perspectives including financial, patient, internal processes, and learning","A tool for balancing the budget","A method for scoring medical exams","A patient satisfaction survey"], correctIndex: 0, rationale: "A balanced scorecard measures organizational performance across four perspectives: financial, customer/patient, internal processes, and learning/growth.", difficulty: 2, category: "Data Analytics & Quality", topic: "Performance Measurement" },
  { id: "him-108", stem: "The False Claims Act prohibits:", options: ["Knowingly submitting false/fraudulent claims for government payment","All medical errors regardless of intent","Patients from filing insurance claims","Providers from treating uninsured patients"], correctIndex: 0, rationale: "The FCA prohibits knowingly submitting false claims. 'Knowingly' includes actual knowledge, deliberate ignorance, or reckless disregard.", difficulty: 2, category: "Compliance & Legal", topic: "Healthcare Fraud Laws" },
  { id: "him-109", stem: "Healthcare compliance programs prevent, detect, and correct:", options: ["Violations of laws, regulations, and organizational policies","All employee disagreements","Budget overruns","Equipment malfunctions"], correctIndex: 0, rationale: "Compliance programs follow OIG's seven elements: written policies, compliance officer, training, hotline, auditing, enforcement, and response to offenses.", difficulty: 1, category: "Compliance & Legal", topic: "Compliance Programs" },
  { id: "him-110", stem: "The Anti-Kickback Statute prohibits:", options: ["Offering/receiving anything of value for referrals of federal healthcare program patients","Free community health screenings","Employee health insurance benefits","Publishing clinical research"], correctIndex: 0, rationale: "AKS prohibits offering/paying/soliciting/receiving anything of value to induce referrals for federally reimbursable services.", difficulty: 2, category: "Compliance & Legal", topic: "Anti-Kickback Statute" },
  { id: "him-111", stem: "Medical record retention for adults is typically:", options: ["5-10 years from last encounter (varies by state)","1 year","Indefinitely for all records","30 days after discharge"], correctIndex: 0, rationale: "Requirements vary by state (5-10 years typically). Federal requirements (Medicare/Medicaid) add additional periods. Follow longest applicable requirement.", difficulty: 2, category: "Compliance & Legal", topic: "Record Retention" },
  { id: "him-112", stem: "The Stark Law prohibits:", options: ["Physician self-referrals for designated health services to entities with financial relationships, unless excepted","All physician referrals","Physicians from owning equipment","Hospitals from employing physicians"], correctIndex: 0, rationale: "Stark is a strict liability statute prohibiting referrals for DHS to entities with which the physician has a financial relationship, unless an exception applies.", difficulty: 3, category: "Compliance & Legal", topic: "Stark Law" },
  { id: "him-113", stem: "A pattern of upcoding E/M services found by OIG audit is:", options: ["Healthcare fraud/abuse requiring corrective action and potential penalties","Normal billing variation","Acceptable coding practice","Minor documentation issue"], correctIndex: 0, rationale: "Systematic upcoding = fraud/abuse. OIG can impose civil monetary penalties, program exclusion, and Corporate Integrity Agreements.", difficulty: 2, category: "Compliance & Legal", topic: "Fraud & Abuse" },
  { id: "him-114", stem: "A Corporate Integrity Agreement (CIA) is:", options: ["A settlement between an entity and OIG requiring compliance measures as alternative to exclusion","A merger agreement","An EHR vendor contract","A compliance officer employment agreement"], correctIndex: 0, rationale: "CIAs require specific compliance measures (monitoring, reporting, training) for typically 5 years as an alternative to federal program exclusion.", difficulty: 3, category: "Compliance & Legal", topic: "Enforcement Actions" },
  { id: "him-115", stem: "The OIG Work Plan:", options: ["Identifies areas of healthcare compliance the OIG will focus on for the coming year","Lists all healthcare workers in the US","Details hospital construction projects","Outlines physician vacation policies"], correctIndex: 0, rationale: "The OIG Work Plan identifies focus areas for audits, evaluations, and investigations. Healthcare organizations should review it annually to assess compliance risks.", difficulty: 2, category: "Compliance & Legal", topic: "OIG Oversight" },
  { id: "him-116", stem: "Qui tam provisions under the False Claims Act allow:", options: ["Private individuals (whistleblowers) to file lawsuits on behalf of the government against fraudulent entities","Government agencies to sue each other","Patients to sue for malpractice","Insurance companies to deny all claims"], correctIndex: 0, rationale: "Qui tam allows whistleblowers (relators) to file lawsuits against entities defrauding the government. Relators may receive 15-30% of recovered funds.", difficulty: 3, category: "Compliance & Legal", topic: "Whistleblower Protections" },
  { id: "him-117", stem: "What is voluntary self-disclosure in healthcare compliance?", options: ["A provider voluntarily reports potential fraud/abuse to the OIG, often resulting in reduced penalties","An employee reporting workplace injuries","A patient disclosing medical history","A vendor disclosing product specifications"], correctIndex: 0, rationale: "The OIG's Self-Disclosure Protocol allows providers to voluntarily report potential fraud, which typically results in lower penalties and avoidance of exclusion.", difficulty: 2, category: "Compliance & Legal", topic: "Self-Disclosure" },
  { id: "him-118", stem: "The primary function of an HIE is:", options: ["Facilitating electronic sharing of health information among organizations","Providing direct patient care","Manufacturing medical devices","Training healthcare workers"], correctIndex: 0, rationale: "HIEs enable electronic sharing of health information among different healthcare organizations for improved care coordination.", difficulty: 1, category: "Health Information Exchange", topic: "HIE Fundamentals" },
  { id: "him-119", stem: "The centralized HIE model:", options: ["Stores data in a central repository for participants to query","Keeps all data at source organizations only","Requires patients to carry their records","Has no central infrastructure"], correctIndex: 0, rationale: "Centralized model stores aggregated data centrally. Federated keeps data at source. Hybrid combines both.", difficulty: 2, category: "Health Information Exchange", topic: "HIE Models" },
  { id: "him-120", stem: "TEFCA was established to:", options: ["Create a universal framework for nationwide health information exchange","Replace all EHR systems","Eliminate patient consent","Standardize hospital architecture"], correctIndex: 0, rationale: "TEFCA creates a 'network of networks' framework where QHINs exchange data under common governance and technical rules.", difficulty: 3, category: "Health Information Exchange", topic: "TEFCA" },
  { id: "him-121", stem: "Consent management in HIE refers to:", options: ["Managing patient preferences for sharing health information across organizations","Surgical consent management","Employment contracts","Insurance claim approvals"], correctIndex: 0, rationale: "HIE consent management captures and enforces patient preferences for data sharing. Models: opt-in, opt-out, and no-consent.", difficulty: 2, category: "Health Information Exchange", topic: "Consent Management" },
  { id: "him-122", stem: "Direct messaging in HIE is:", options: ["Secure, point-to-point encrypted health information exchange between trusted participants","SMS texting of patient info","Social media messaging between providers","Faxing medical records"], correctIndex: 0, rationale: "Direct Standard provides secure, point-to-point, authenticated, encrypted health information exchange using internet-based protocols.", difficulty: 2, category: "Health Information Exchange", topic: "Direct Messaging" },
  { id: "him-123", stem: "What is a Record Locator Service (RLS) in an HIE?", options: ["An index that identifies which organizations hold records for a specific patient without storing clinical data","A physical records storage facility","A filing system for paper charts","A database of all clinical data"], correctIndex: 0, rationale: "An RLS maintains a master patient index that points to where records exist without storing the actual clinical data, enabling federated query models.", difficulty: 2, category: "Health Information Exchange", topic: "HIE Architecture" },
  { id: "him-124", stem: "Public health reporting through HIE enables:", options: ["Automated electronic reporting of notifiable conditions to public health agencies","Manual paper-based disease reporting","Patient-initiated health surveys","Hospital marketing campaigns"], correctIndex: 0, rationale: "HIE-enabled public health reporting automates electronic submission of notifiable conditions, syndromic surveillance data, and immunization records to public health agencies.", difficulty: 2, category: "Health Information Exchange", topic: "Public Health Reporting" },
  { id: "him-125", stem: "The Sequoia Project is related to HIE as:", options: ["The Recognized Coordinating Entity (RCE) for TEFCA, managing the Common Agreement","A pharmaceutical company","A medical device manufacturer","An insurance company"], correctIndex: 0, rationale: "The Sequoia Project serves as the RCE designated by ONC to develop, implement, and maintain TEFCA's Common Agreement and the Qualified Health Information Network (QHIN) designation process.", difficulty: 3, category: "Health Information Exchange", topic: "TEFCA Governance" },
  { id: "him-126", stem: "What does the 7th character 'S' indicate in ICD-10-CM injury codes?", options: ["Sequela - a late effect of a previous injury","Initial encounter","Subsequent encounter","Status post surgery"], correctIndex: 0, rationale: "The 7th character 'S' indicates sequela — a condition that is a direct result of a previous injury/illness after the acute phase has ended.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Extension Characters" },
  { id: "him-127", stem: "A patient has a malignant neoplasm of the overlapping sites of the right breast. Which code is assigned?", options: ["C50.811","C50.911","C50.111","C50.211"], correctIndex: 0, rationale: "C50.811 covers malignant neoplasm of overlapping sites of right breast when the tumor spans multiple quadrants.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Neoplasm Coding" },
  { id: "him-128", stem: "When is code Z23 (Encounter for immunization) used as the first-listed diagnosis?", options: ["When the sole purpose of the visit is for immunization","Never as first-listed","Only for childhood vaccines","Only in hospital settings"], correctIndex: 0, rationale: "Z23 is used as the first-listed diagnosis when the encounter is solely for receiving an immunization.", difficulty: 1, category: "ICD-10-CM/PCS Coding", topic: "Z Code Usage" },
  { id: "him-129", stem: "What is the correct ICD-10-PCS root operation for a diagnostic bone marrow biopsy?", options: ["Extraction","Excision","Inspection","Drainage"], correctIndex: 0, rationale: "Bone marrow biopsy uses the root operation Extraction — pulling or stripping out all or a portion of a body part by force.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "PCS Root Operations" },
  { id: "him-130", stem: "A patient is admitted with acute ST-elevation myocardial infarction of the anterior wall. The correct code is:", options: ["I21.09","I21.19","I21.29","I25.10"], correctIndex: 0, rationale: "I21.09 is for acute STEMI of the anterior wall. ICD-10-CM differentiates by wall (anterior, inferior, other sites) and type (STEMI vs NSTEMI).", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Cardiac Coding" },
  { id: "him-131", stem: "How should drug toxicity be coded when the patient takes a medication as prescribed?", options: ["Adverse effect code (T36-T50 with 5th character 5) plus the condition caused","Poisoning code (accidental)","Underdosing code","No code needed for prescribed medications"], correctIndex: 0, rationale: "When a drug is correctly prescribed and properly administered but causes an adverse effect, use the adverse effect code (5th character 5) plus codes for the manifestations.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Drug Coding" },
  { id: "him-132", stem: "What is an Excludes2 note in ICD-10-CM?", options: ["The excluded condition is not part of the condition but may be coded together if both exist","The codes are mutually exclusive and cannot be used together","The condition is included in the code","Use an additional code"], correctIndex: 0, rationale: "Excludes2 means 'Not included here' but both conditions can exist together and both codes may be reported if documented.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Coding Conventions" },
  { id: "him-133", stem: "A patient is diagnosed with sepsis due to E. coli with associated acute organ dysfunction (acute kidney failure). What codes are needed?", options: ["A41.51 followed by R65.20 and N17.9","A41.51 only","R65.20 only","N17.9 only"], correctIndex: 0, rationale: "Sepsis with organ dysfunction requires: sepsis code (A41.51), severe sepsis code (R65.20), and the specific organ dysfunction code (N17.9 for AKI).", difficulty: 4, category: "ICD-10-CM/PCS Coding", topic: "Sepsis Coding" },
  { id: "him-134", stem: "In ICD-10-PCS, what is the root operation for a total hip replacement?", options: ["Replacement","Supplement","Revision","Insertion"], correctIndex: 0, rationale: "Total hip replacement uses root operation Replacement — putting in biological or synthetic material that physically takes the place of a body part.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "PCS Root Operations" },
  { id: "him-135", stem: "What is the significance of the 'and' convention in ICD-10-CM?", options: ["It should be interpreted as 'and/or'","It means both conditions must be present","It is used only in exclusion notes","It indicates mandatory sequencing"], correctIndex: 0, rationale: "In ICD-10-CM, 'and' is interpreted as 'and/or' — either or both conditions may apply.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Coding Conventions" },
  { id: "him-136", stem: "How is laterality indicated in ICD-10-CM codes?", options: ["Through a specific character position in the code"," typically the 5th or 6th character","Only in the code description text","Through a modifier","It is not indicated in ICD-10-CM"], correctIndex: 0, rationale: "ICD-10-CM incorporates laterality (right/left/bilateral/unspecified) directly into the code through character positions, typically 5th or 6th.", difficulty: 1, category: "ICD-10-CM/PCS Coding", topic: "Code Structure" },
  { id: "him-137", stem: "A patient has chronic kidney disease stage 4 on dialysis. Which codes should be reported?", options: ["N18.4 and Z99.2","N18.4 only","Z99.2 only","N18.6"], correctIndex: 0, rationale: "Report both N18.4 (CKD stage 4) and Z99.2 (dependence on renal dialysis). The status code Z99.2 indicates the ongoing dialysis treatment.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "CKD Coding" },
  { id: "him-138", stem: "What is the correct approach for coding a condition described as 'impending' or 'threatened'?", options: ["Code the condition as if it exists unless the classification has a specific entry for impending/threatened","Do not code until the condition fully manifests","Code only signs and symptoms","Code as a history of the condition"], correctIndex: 0, rationale: "If the Alphabetic Index or Tabular List has a specific entry for 'impending' or 'threatened,' code it. Otherwise, code the existing condition that led to the concern.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Uncertain Diagnoses" },
  { id: "him-139", stem: "What is the purpose of modifier -76?", options: ["Repeat procedure by the same physician on the same day","Distinct procedural service","Bilateral procedure","Professional component"], correctIndex: 0, rationale: "Modifier -76 indicates a procedure or service was repeated by the same physician on the same day. This differentiates from a duplicate claim.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "CPT Modifiers" },
  { id: "him-140", stem: "When should modifier -57 be used?", options: ["Decision for surgery made during the E/M encounter","Discontinued procedure","Reduced services","Repeat procedure by different physician"], correctIndex: 0, rationale: "Modifier -57 indicates the decision for surgery was made during the E/M encounter. It prevents the E/M from being bundled into the global surgical package.", difficulty: 3, category: "CPT/HCPCS Coding", topic: "CPT Modifiers" },
  { id: "him-141", stem: "An NCCI edit indicates two codes are bundled. What does this mean?", options: ["The two procedures are typically performed together and only the comprehensive code should be reported","The codes must always be reported together","The codes are never performed together","One code replaces the other permanently"], correctIndex: 0, rationale: "NCCI (National Correct Coding Initiative) edits identify code pairs that should not typically be billed together because one is a component of the other.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "NCCI Edits" },
  { id: "him-142", stem: "What is the difference between a consultation and a referral in CPT coding?", options: ["A consultation includes the consultant's opinion/advice with a report back; a referral transfers care","They are identical in coding","Consultations are always inpatient","Referrals require modifier -25"], correctIndex: 0, rationale: "A consultation (99241-99255) involves rendering an opinion at the request of another physician with a report back. A referral transfers management of the patient's condition.", difficulty: 3, category: "CPT/HCPCS Coding", topic: "Consultation Coding" },
  { id: "him-143", stem: "How is telehealth/telemedicine service indicated using modifiers?", options: ["Modifier -95 for synchronous telemedicine services","Modifier -25","Modifier -51","Modifier -59"], correctIndex: 0, rationale: "Modifier -95 indicates a synchronous telemedicine service rendered via real-time interactive audio and video. Place of service 02 may also be used.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "Telehealth Coding" },
  { id: "him-144", stem: "Prolonged services codes are used when:", options: ["The physician spends time beyond what is typical for the highest-level E/M service","Any visit lasts more than 15 minutes","The patient requests a longer appointment","Multiple diagnoses are discussed"], correctIndex: 0, rationale: "Prolonged services codes (99354-99357 or 99417) are reported when direct patient contact exceeds the typical time for the E/M service by the defined threshold.", difficulty: 3, category: "CPT/HCPCS Coding", topic: "E/M Coding" },
  { id: "him-145", stem: "What is the AMA RVU system?", options: ["A method for determining relative work"," practice expense"," and malpractice costs for each CPT code","A rating system for medical schools","A physician credentialing system","A patient satisfaction metric"], correctIndex: 0, rationale: "The Resource-Based Relative Value Scale (RBRVS) assigns Relative Value Units (RVUs) to each CPT code: work RVU, practice expense RVU, and malpractice RVU, multiplied by a conversion factor.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "Payment Systems" },
  { id: "him-146", stem: "Correct coding for casting application in the ED for a fracture includes:", options: ["The casting is included in the fracture care global package if the same physician manages the fracture","Separate coding for the cast and the fracture","Only the cast application code","Only the fracture reduction code"], correctIndex: 0, rationale: "Initial casting or splinting is included in the global surgical package for fracture care when performed by the treating physician. Separate coding would be appropriate only if the cast is applied by a different provider.", difficulty: 3, category: "CPT/HCPCS Coding", topic: "Global Period" },
  { id: "him-147", stem: "HCPCS Level II modifier -LT indicates:", options: ["Left side","Low threshold","Laboratory test","Long-term"], correctIndex: 0, rationale: "HCPCS modifier -LT indicates the procedure was performed on the left side of the body. -RT indicates right side.", difficulty: 1, category: "CPT/HCPCS Coding", topic: "HCPCS Modifiers" },
  { id: "him-148", stem: "What is the correct way to report surgical pathology with multiple specimens?", options: ["Each specimen examined by the pathologist is reported separately using the appropriate level code","Only report the highest level specimen","Report one code for all specimens combined","Use modifier -51 with one code"], correctIndex: 0, rationale: "Each separately identifiable specimen examined by the pathologist is reported separately. Level is determined by what the specimen is, not how many are examined together.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "Pathology Coding" },
  { id: "him-149", stem: "A subpoena requests medical records. Under HIPAA, the provider should:", options: ["Verify the subpoena meets HIPAA requirements (qualified protective order or patient notice) before releasing","Immediately release all records","Ignore the subpoena","Release records without any verification"], correctIndex: 0, rationale: "HIPAA permits disclosure pursuant to court orders and subpoenas, but subpoenas require either a qualified protective order or satisfactory assurance that the patient was notified.", difficulty: 3, category: "HIPAA Privacy & Security", topic: "Legal Disclosures" },
  { id: "him-150", stem: "Under HIPAA, a healthcare provider can share PHI with a patient's family member:", options: ["When the patient is present and does not object"," or when in the patient's best interest if incapacitated","Never without written authorization","Only if the family member is the legal next of kin","Only for billing purposes"], correctIndex: 0, rationale: "HIPAA permits sharing PHI with family/friends involved in care when the patient is present and does not object, or when the patient is incapacitated and disclosure is in their best interest.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Disclosure Rules" },
  { id: "him-151", stem: "HIPAA requires workforce training on privacy and security:", options: ["For all workforce members upon hire and periodically thereafter","Only for IT staff","Only for clinical staff","Only when a breach occurs"], correctIndex: 0, rationale: "HIPAA requires training for ALL workforce members (employees, volunteers, trainees) on privacy/security policies upon hire and periodically. Documentation of training must be maintained.", difficulty: 1, category: "HIPAA Privacy & Security", topic: "Training Requirements" },
  { id: "him-152", stem: "What is a Notice of Privacy Practices (NPP)?", options: ["A document explaining how the covered entity uses and discloses PHI and patients' rights","A consent form for surgery","An insurance verification form","A billing statement"], correctIndex: 0, rationale: "The NPP explains how PHI is used/disclosed, patients' rights regarding their PHI, and the entity's legal duties. Must be provided to patients and posted prominently.", difficulty: 1, category: "HIPAA Privacy & Security", topic: "Privacy Practices" },
  { id: "him-153", stem: "Which of the following would violate the HIPAA minimum necessary standard?", options: ["A billing clerk accessing a patient's psychiatric notes when only demographic data is needed for a claim","A physician reviewing a patient's full medical record before surgery","A nurse accessing vital signs for a patient under their care","A lab technician viewing ordered test results"], correctIndex: 0, rationale: "The minimum necessary standard is violated when access exceeds what's needed for the specific purpose. A billing clerk needs only demographics, not clinical notes.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Minimum Necessary" },
  { id: "him-154", stem: "An employee accesses their neighbor's medical record out of curiosity. This is:", options: ["A HIPAA violation — snooping/unauthorized access of PHI","Acceptable if no information is shared","A violation only if the employee is a physician","Not a violation if the records are not printed"], correctIndex: 0, rationale: "Accessing PHI without a legitimate work-related purpose ('snooping') is a HIPAA violation regardless of whether information is shared. It is a violation of the minimum necessary standard.", difficulty: 1, category: "HIPAA Privacy & Security", topic: "Unauthorized Access" },
  { id: "him-155", stem: "How long must HIPAA-related documentation (policies, procedures, training records) be retained?", options: ["6 years from the date of creation or last effective date","1 year","3 years","10 years"], correctIndex: 0, rationale: "HIPAA requires covered entities to retain policies, procedures, and required documentation for 6 years from the date of creation or last effective date, whichever is later.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Record Retention" },
  { id: "him-156", stem: "The HIPAA Security Rule specifically protects:", options: ["Electronic PHI (ePHI) only","All forms of PHI including paper and oral","Only paper records","Only information transmitted via fax"], correctIndex: 0, rationale: "The Security Rule specifically applies to ePHI — PHI in electronic form. The Privacy Rule covers all forms of PHI (paper, oral, electronic).", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Security Rule Scope" },
  { id: "him-157", stem: "What does the ONC (Office of the National Coordinator) do?", options: ["Coordinates national health IT efforts and certifies EHR technology","Manufactures EHR software","Provides direct patient care","Administers Medicare payments"], correctIndex: 0, rationale: "ONC coordinates national health IT efforts, sets standards and certification criteria, and supports health information exchange.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Health IT Governance" },
  { id: "him-158", stem: "What is structured data in an EHR?", options: ["Data entered in predefined fields with standardized formats that can be queried and analyzed","Free-text narrative notes","Scanned paper documents","Voice recordings"], correctIndex: 0, rationale: "Structured data uses predefined fields, codes, and formats (drop-downs, checkboxes, coded entries) enabling computational analysis. Free text is unstructured.", difficulty: 1, category: "EHR Systems & Health IT", topic: "Data Types" },
  { id: "him-159", stem: "What is a master patient index (MPI)?", options: ["A database linking patient records across multiple systems using unique identifiers","A list of all physicians on staff","An inventory of medical equipment","A schedule of all patient appointments"], correctIndex: 0, rationale: "An MPI maintains a unique identifier for each patient to link records across multiple systems, preventing duplicates and ensuring accurate record matching.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Patient Identification" },
  { id: "him-160", stem: "Health Level Seven (HL7) version 2.x messages are used for:", options: ["Transmitting administrative and clinical data between healthcare systems","Creating patient-facing websites","Designing hospital floor plans","Managing pharmacy inventory"], correctIndex: 0, rationale: "HL7 v2.x is the most widely used healthcare messaging standard for exchanging data (ADT, orders, results, scheduling) between systems.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Data Exchange Standards" },
  { id: "him-161", stem: "What is the purpose of a health information exchange consent directive?", options: ["Documenting a patient's preference for sharing their health data through the HIE","Consent for surgery","Authorization for insurance billing","Agreement to follow treatment plans"], correctIndex: 0, rationale: "An HIE consent directive documents whether a patient opts in or out of health information sharing through an HIE, respecting their autonomy and HIPAA rights.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Patient Consent" },
  { id: "him-162", stem: "ICD-10-CM mapping in an EHR system refers to:", options: ["Linking clinical documentation elements to appropriate ICD-10-CM codes for accurate coding","Physical mapping of hospital departments","Genetic mapping of patient DNA","Mapping patient transport routes"], correctIndex: 0, rationale: "ICD-10-CM mapping connects documented clinical terms, diagnoses, and conditions to their corresponding ICD-10-CM codes, supporting computer-assisted coding.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Clinical Coding" },
  { id: "him-163", stem: "What is natural language processing (NLP) in health IT?", options: ["Technology that extracts meaningful information from unstructured clinical text","A system for translating medical documents to different languages","A method for processing insurance claims","A technique for scheduling appointments"], correctIndex: 0, rationale: "NLP uses computational linguistics and AI to extract structured data (diagnoses, procedures, medications) from unstructured clinical narratives like progress notes.", difficulty: 3, category: "EHR Systems & Health IT", topic: "Advanced Analytics" },
  { id: "him-164", stem: "What is a superbill?", options: ["A form listing services"," procedures"," and diagnoses from a patient encounter used for billing","An exceptionally large medical bill","A special insurance plan","A government subsidy for healthcare"], correctIndex: 0, rationale: "A superbill (encounter form/charge ticket) lists commonly used CPT/ICD codes for a practice, checked off during the encounter to capture billable services.", difficulty: 1, category: "Revenue Cycle Management", topic: "Charge Capture" },
  { id: "him-165", stem: "Value-based reimbursement differs from fee-for-service by:", options: ["Tying payment to quality outcomes and cost efficiency rather than volume of services","Paying more for each individual service","Eliminating all insurance requirements","Only paying for emergency services"], correctIndex: 0, rationale: "Value-based payment models (ACOs, bundled payments, P4P) reward quality, outcomes, and efficiency rather than paying for each discrete service rendered.", difficulty: 2, category: "Revenue Cycle Management", topic: "Payment Models" },
  { id: "him-166", stem: "What is a clearinghouse in healthcare billing?", options: ["An intermediary that receives claims from providers"," reformats them"," and forwards to payers","A hospital laundry facility","A pharmaceutical distribution center","A medical records storage company"], correctIndex: 0, rationale: "Healthcare clearinghouses receive claims from providers, check for errors, reformat to standard transaction formats (837), and transmit to appropriate payers.", difficulty: 1, category: "Revenue Cycle Management", topic: "Claims Processing" },
  { id: "him-167", stem: "Accounts receivable aging reports categorize outstanding claims by:", options: ["Age of the claim (0-30"," 31-60"," 61-90"," 90+ days)","Alphabetical patient order","Type of insurance","Physician who provided service"], correctIndex: 0, rationale: "A/R aging reports categorize outstanding receivables by time since billing. Older claims are harder to collect, so monitoring aging helps prioritize follow-up efforts.", difficulty: 2, category: "Revenue Cycle Management", topic: "Revenue Cycle Metrics" },
  { id: "him-168", stem: "What is coordination of benefits (COB)?", options: ["Determining the order of payment responsibility when a patient has multiple insurance plans","Coordinating patient appointments","Benefits enrollment process","Coordinating physician schedules"], correctIndex: 0, rationale: "COB determines primary and secondary payer responsibility when a patient has coverage under multiple insurance plans, preventing overpayment.", difficulty: 2, category: "Revenue Cycle Management", topic: "Insurance Coordination" },
  { id: "him-169", stem: "A managed care contract typically includes:", options: ["Negotiated fee schedules"," covered services"," utilization management requirements"," and credentialing standards","Only the provider's billing rates","Only the payer's rules","A list of patient names"], correctIndex: 0, rationale: "Managed care contracts define the relationship between provider and payer including negotiated rates, covered services, UM requirements, credentialing, and quality standards.", difficulty: 2, category: "Revenue Cycle Management", topic: "Managed Care" },
  { id: "him-170", stem: "What is balance billing?", options: ["Billing the patient for the difference between the provider's charge and the insurance allowed amount","Billing for balancing exercises","Creating a balanced budget for the practice","Billing equal amounts to multiple insurance plans"], correctIndex: 0, rationale: "Balance billing charges patients for the difference between billed charges and insurance allowed amounts. It's prohibited for in-network providers in most managed care contracts.", difficulty: 2, category: "Revenue Cycle Management", topic: "Patient Billing" },
  { id: "him-171", stem: "The CMS-1500 form is used for:", options: ["Submitting professional claims to Medicare and other payers","Hospital inpatient claims","Pharmacy claims","Durable medical equipment claims only"], correctIndex: 0, rationale: "The CMS-1500 (or its electronic equivalent 837P) is the standard form for professional claims from physicians, suppliers, and other non-institutional providers.", difficulty: 1, category: "Revenue Cycle Management", topic: "Claims Submission" },
  { id: "him-172", stem: "What is a DRG (Diagnosis Related Group)?", options: ["A patient classification system that categorizes inpatient stays into groups for prospective payment","A type of medication","A diagnostic imaging technique","A type of surgical instrument"], correctIndex: 0, rationale: "DRGs classify inpatient hospital stays into clinically coherent groups that consume similar resources, forming the basis of Medicare's inpatient prospective payment system (IPPS).", difficulty: 2, category: "Revenue Cycle Management", topic: "Payment Systems" },
  { id: "him-173", stem: "What is a 'clinical validation' query?", options: ["A query asking the physician to clinically validate a diagnosis or provide supporting clinical indicators","A query about patient demographics","A billing department question","A lab test validation"], correctIndex: 0, rationale: "Clinical validation queries ask physicians whether clinical evidence supports a diagnosis. This differs from clarification queries that seek additional specificity.", difficulty: 3, category: "Clinical Documentation Improvement", topic: "CDI Queries" },
  { id: "him-174", stem: "Severity of Illness (SOI) and Risk of Mortality (ROM) are affected by:", options: ["The specificity and accuracy of documented diagnoses and procedures","Only the length of stay","Only the patient's age","Only the principal diagnosis"], correctIndex: 0, rationale: "SOI and ROM calculations consider all documented diagnoses, comorbidities, complications, and procedures. More specific documentation improves accuracy of these measures.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "Severity Metrics" },
  { id: "him-175", stem: "Which documentation strategy best captures the complexity of a multi-system patient?", options: ["Documenting each active condition with specificity"," including cause-and-effect relationships between conditions","Writing lengthy narrative notes","Documenting only the primary diagnosis","Using abbreviations extensively"], correctIndex: 0, rationale: "Complex patients require documentation of each active condition with specificity, linking related conditions (e.g., diabetes causing CKD), and noting severity/acuity.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "Documentation Strategies" },
  { id: "him-176", stem: "A CDI specialist notices a lab value indicating acute kidney injury but no physician documentation of it. The appropriate action is:", options: ["Query the physician to document the clinical significance of the lab finding","Code acute kidney injury based on lab values alone","Ignore the finding","Document the diagnosis yourself"], correctIndex: 0, rationale: "CDI specialists cannot diagnose — they must query physicians about clinically significant lab findings. Coders should not code diagnoses from lab values without physician confirmation.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "CDI Best Practices" },
  { id: "him-177", stem: "Mortality review in CDI focuses on:", options: ["Ensuring documentation of all conditions contributing to mortality is complete and accurate for quality reporting","Determining legal cause of death","Assigning blame for patient deaths","Reducing autopsy rates"], correctIndex: 0, rationale: "CDI mortality reviews ensure that all contributing conditions are accurately documented, which impacts quality metrics (observed vs. expected mortality), hospital ratings, and risk-adjusted data.", difficulty: 3, category: "Clinical Documentation Improvement", topic: "Mortality Review" },
  { id: "him-178", stem: "Clinical documentation should support medical necessity by:", options: ["Linking diagnoses to tests"," procedures"," and treatments ordered","Using as many diagnosis codes as possible","Writing longer progress notes","Including patient billing information"], correctIndex: 0, rationale: "Medical necessity requires documentation that links each diagnostic test, procedure, and treatment to a documented clinical indication, supporting both coding and payer requirements.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "Medical Necessity" },
  { id: "him-179", stem: "A p-value less than 0.05 in healthcare research indicates:", options: ["Statistical significance — results are unlikely due to chance alone","No significant findings","Perfect correlation","Clinical significance"], correctIndex: 0, rationale: "A p-value < 0.05 means there is less than a 5% probability that the observed results occurred by chance, suggesting statistical significance. Note: statistical significance doesn't always mean clinical significance.", difficulty: 2, category: "Data Analytics & Quality", topic: "Biostatistics" },
  { id: "him-180", stem: "What is a control chart used for in quality improvement?", options: ["Monitoring process variation over time to distinguish common cause from special cause variation","Controlling employee access to data","Charting patient vital signs","Controlling inventory levels"], correctIndex: 0, rationale: "Control charts display process data over time with control limits. Points within limits = common cause (inherent) variation. Points outside = special cause (assignable) variation requiring investigation.", difficulty: 3, category: "Data Analytics & Quality", topic: "Quality Improvement Tools" },
  { id: "him-181", stem: "Benchmarking in healthcare quality involves:", options: ["Comparing an organization's performance against best practices or standards from similar organizations","Setting the lowest acceptable standard","Comparing only financial data","Using only internal historical data"], correctIndex: 0, rationale: "Benchmarking compares performance metrics against industry best practices, peer organizations, or national standards to identify improvement opportunities.", difficulty: 2, category: "Data Analytics & Quality", topic: "Performance Improvement" },
  { id: "him-182", stem: "What is the purpose of a root cause analysis (RCA)?", options: ["Identifying the fundamental underlying causes of adverse events or near misses to prevent recurrence","Blaming individual staff members","Calculating costs of errors","Reviewing patient satisfaction scores"], correctIndex: 0, rationale: "RCA systematically identifies the deepest underlying causes of adverse events. It focuses on systems and processes rather than individuals, with the goal of implementing system changes.", difficulty: 2, category: "Data Analytics & Quality", topic: "Patient Safety" },
  { id: "him-183", stem: "Sensitivity of a diagnostic test measures:", options: ["The test's ability to correctly identify those who have the disease (true positive rate)","The test's ability to correctly identify those without disease","The likelihood the test result is correct","The cost-effectiveness of the test"], correctIndex: 0, rationale: "Sensitivity = true positives / (true positives + false negatives). High sensitivity means few false negatives — good for screening. Specificity measures true negatives.", difficulty: 3, category: "Data Analytics & Quality", topic: "Biostatistics" },
  { id: "him-184", stem: "What does the term 'population health management' refer to?", options: ["An approach to improve health outcomes of a defined group by monitoring and identifying individuals at risk","Managing hospital admissions","Population census data collection","Managing staff schedules"], correctIndex: 0, rationale: "Population health management uses data analytics to identify health risks within a defined population, stratify risk levels, and implement targeted interventions to improve outcomes and reduce costs.", difficulty: 2, category: "Data Analytics & Quality", topic: "Population Health" },
  { id: "him-185", stem: "What is data mining in healthcare?", options: ["Using algorithms to discover patterns and relationships in large datasets","Manually reviewing individual patient charts","Physical mining of natural resources","Data entry into the EHR"], correctIndex: 0, rationale: "Data mining applies statistical and computational algorithms to large healthcare datasets to discover previously unknown patterns, correlations, and trends for clinical and operational insights.", difficulty: 3, category: "Data Analytics & Quality", topic: "Advanced Analytics" },
  { id: "him-186", stem: "The balanced scorecard perspective that focuses on employee training and knowledge is:", options: ["Learning and growth perspective","Financial perspective","Customer/patient perspective","Internal process perspective"], correctIndex: 0, rationale: "The learning and growth perspective focuses on employee development, training, knowledge management, and organizational culture — the foundation for achieving goals in other perspectives.", difficulty: 2, category: "Data Analytics & Quality", topic: "Performance Measurement" },
  { id: "him-187", stem: "Which measure calculates the number of new cases of a disease in a population during a specific time period?", options: ["Incidence rate","Prevalence rate","Mortality rate","Morbidity rate"], correctIndex: 0, rationale: "Incidence = new cases per population per time period. Prevalence = total existing cases at a point in time. Incidence measures risk of developing the disease.", difficulty: 2, category: "Data Analytics & Quality", topic: "Epidemiology" },
  { id: "him-188", stem: "A fishbone (Ishikawa) diagram is used to:", options: ["Identify and organize potential causes of a problem into categories","Track financial performance","Schedule patient appointments","Document patient assessments"], correctIndex: 0, rationale: "Fishbone diagrams organize potential causes into categories (people, process, equipment, materials, environment, management) to facilitate root cause analysis.", difficulty: 2, category: "Data Analytics & Quality", topic: "Quality Improvement Tools" },
  { id: "him-189", stem: "The Conditions of Participation (CoPs) are:", options: ["Standards that healthcare organizations must meet to participate in Medicare/Medicaid programs","Optional quality guidelines","State licensing requirements only","Joint Commission standards"], correctIndex: 0, rationale: "CoPs are federal standards in the Code of Federal Regulations that healthcare organizations must meet to participate in and receive payment from Medicare/Medicaid.", difficulty: 2, category: "Compliance & Legal", topic: "Regulatory Requirements" },
  { id: "him-190", stem: "Informed consent documentation must include:", options: ["Nature of the procedure"," risks"," benefits"," alternatives"," and the patient's agreement","Only the patient's signature","Only the procedure name","Only the physician's signature"], correctIndex: 0, rationale: "Informed consent must document: nature of the proposed procedure, material risks, expected benefits, alternatives, and the patient's voluntary agreement.", difficulty: 2, category: "Compliance & Legal", topic: "Consent Requirements" },
  { id: "him-191", stem: "EMTALA (Emergency Medical Treatment and Labor Act) requires:", options: ["Hospital EDs to provide medical screening and stabilizing treatment regardless of ability to pay","Only treating patients with insurance","Providing free care to all patients","Hospital EDs to close when full"], correctIndex: 0, rationale: "EMTALA requires Medicare-participating hospitals with EDs to provide a medical screening exam and stabilizing treatment to anyone regardless of insurance status or ability to pay.", difficulty: 2, category: "Compliance & Legal", topic: "EMTALA" },
  { id: "him-192", stem: "What is the purpose of an exclusion check against the OIG List of Excluded Individuals/Entities (LEIE)?", options: ["Ensuring the organization does not employ or contract with individuals excluded from federal healthcare programs","Checking patient insurance status","Verifying physician board certification","Confirming drug formulary listings"], correctIndex: 0, rationale: "Organizations must check the LEIE before hiring employees, contractors, or vendors. Employing excluded individuals can result in civil monetary penalties per item/service.", difficulty: 2, category: "Compliance & Legal", topic: "Compliance Screening" },
  { id: "him-193", stem: "Medical identity theft occurs when:", options: ["Someone uses another person's health insurance or personal information to obtain healthcare or submit fraudulent claims","A patient forgets their insurance card","A hospital changes its name","A physician retires"], correctIndex: 0, rationale: "Medical identity theft involves using someone's health identity to obtain services, drugs, or submit false claims. It can result in corrupted medical records and financial fraud.", difficulty: 2, category: "Compliance & Legal", topic: "Fraud Prevention" },
  { id: "him-194", stem: "Advance directives include:", options: ["Living wills and durable powers of attorney for healthcare","Physician orders only","Insurance authorization forms","Hospital admission agreements"], correctIndex: 0, rationale: "Advance directives include living wills (stating treatment preferences) and durable powers of attorney for healthcare (designating a decision-maker if incapacitated).", difficulty: 1, category: "Compliance & Legal", topic: "Patient Rights" },
  { id: "him-195", stem: "What is a sentinel event?", options: ["An unexpected occurrence involving death or serious injury"," or the risk thereof","Any patient complaint","A routine adverse drug reaction","A scheduled system outage"], correctIndex: 0, rationale: "The Joint Commission defines sentinel events as unexpected occurrences involving death, permanent harm, or severe temporary harm. They require root cause analysis and corrective action.", difficulty: 2, category: "Compliance & Legal", topic: "Patient Safety" },
  { id: "him-196", stem: "Release of information (ROI) procedures must ensure:", options: ["Proper authorization is obtained"," minimum necessary standard is applied"," and disclosures are tracked","Records are released to anyone who requests them","All records are released in their entirety","No tracking of disclosures is needed"], correctIndex: 0, rationale: "ROI requires valid authorization verification, application of minimum necessary, accounting of disclosures, and compliance with state and federal regulations.", difficulty: 2, category: "Compliance & Legal", topic: "Information Release" },
  { id: "him-197", stem: "A federated HIE model:", options: ["Keeps data at the source organizations and queries are distributed across participants","Stores all data centrally","Requires patients to carry USB drives","Has no query capability"], correctIndex: 0, rationale: "In a federated model, data remains with the originating organization. Queries are sent to participants who return relevant results without centrally storing data.", difficulty: 2, category: "Health Information Exchange", topic: "HIE Models" },
  { id: "him-198", stem: "Master Patient Index (MPI) in an HIE context:", options: ["Links patient identities across multiple organizations to enable record matching","Stores all clinical data centrally","Replaces individual organization records","Is used only for billing"], correctIndex: 0, rationale: "The MPI in an HIE maintains a registry of patient identities and links records across organizations using matching algorithms to ensure the right data reaches the right patient.", difficulty: 2, category: "Health Information Exchange", topic: "Patient Matching" },
  { id: "him-199", stem: "Immunization Information Systems (IIS) connected to HIEs:", options: ["Enable providers to access comprehensive immunization histories and report vaccinations electronically","Replace the need for vaccinations","Only store childhood immunization records","Are used exclusively by pharmacies"], correctIndex: 0, rationale: "IIS registries connected to HIEs provide providers with consolidated immunization records, support clinical decision-making for vaccine recommendations, and enable automated reporting.", difficulty: 2, category: "Health Information Exchange", topic: "Public Health Integration" },
  { id: "him-200", stem: "What challenge does patient matching pose for HIEs?", options: ["Inconsistent patient identifiers across systems can lead to duplicate records or incorrect matches","Patients refuse to participate","Technology is too expensive","Legal barriers prevent all matching"], correctIndex: 0, rationale: "Without a universal patient identifier, HIEs must match patients using algorithms analyzing name, DOB, SSN, address, etc. Inconsistencies create duplicates or incorrect matches affecting data quality.", difficulty: 3, category: "Health Information Exchange", topic: "Patient Matching Challenges" },
  { id: "him-201", stem: "Query-based exchange in HIE allows:", options: ["A provider to request information about a specific patient from other participating organizations","Patients to query their own records","Automatic data sharing without provider action","Only emergency department queries"], correctIndex: 0, rationale: "Query-based exchange enables authorized providers to search for and retrieve patient information from other participating organizations on an as-needed basis.", difficulty: 2, category: "Health Information Exchange", topic: "Exchange Methods" },
  { id: "him-202", stem: "What is the ICD-10-CM code for encounter for screening for malignant neoplasm of colon?", options: ["Z12.11","Z12.31","Z80.0","C18.9"], correctIndex: 0, rationale: "Z12.11 is for screening colonoscopy. Screening codes are used when the encounter is for a screening exam in an asymptomatic patient.", difficulty: 1, category: "ICD-10-CM/PCS Coding", topic: "Screening Codes" },
  { id: "him-203", stem: "A patient is admitted with dehydration secondary to gastroenteritis. What is the principal diagnosis?", options: ["The dehydration (E86.0) if it is the condition that necessitated admission","The gastroenteritis","Both coded equally","Neither — use R codes only"], correctIndex: 0, rationale: "The condition that after study is determined to be chiefly responsible for the admission is the principal diagnosis. If dehydration required admission for IV fluids, it may be principal.", difficulty: 3, category: "ICD-10-CM/PCS Coding", topic: "Principal Diagnosis Selection" },
  { id: "him-204", stem: "How are external cause codes (V00-Y99) used in ICD-10-CM?", options: ["As secondary codes to describe the cause, intent, place, and activity related to an injury","As primary diagnosis codes","Only for workers' compensation claims","They replace diagnosis codes"], correctIndex: 0, rationale: "External cause codes are always secondary codes describing how an injury occurred (cause), the intent (accidental, assault, self-harm), the place, and the activity at the time.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "External Cause Codes" },
  { id: "him-205", stem: "A patient with type 1 diabetes presents with diabetic retinopathy. The correct code sequence is:", options: ["E10.319 (T1DM with unspecified diabetic retinopathy without macular edema)","H35.00 followed by E10.9","E10.9 only","H36 only"], correctIndex: 0, rationale: "ICD-10-CM uses combination codes for diabetes with manifestations. E10.319 captures T1DM with unspecified retinopathy without macular edema in a single code.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Diabetes Coding" },
  { id: "him-206", stem: "What is the correct ICD-10-PCS root operation for a coronary artery bypass graft?", options: ["Bypass","Transfer","Replacement","Supplement"], correctIndex: 0, rationale: "Bypass alters the route of passage of contents of a tubular body part. CABG reroutes blood flow around a blocked coronary artery using a bypass root operation.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Cardiac Procedures" },
  { id: "him-207", stem: "What is the correct CPT code for a simple laceration repair of the arm, 5.0 cm?", options: ["12004","12034","12044","13120"], correctIndex: 0, rationale: "CPT 12004 covers simple repair of wounds 2.6-7.5 cm on extremities. Simple repairs involve one-layer closure. Intermediate (12031-12057) involves layered closure.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "Integumentary Coding" },
  { id: "him-208", stem: "Modifier -53 indicates:", options: ["Discontinued procedure due to threat to patient well-being","Repeat procedure","Bilateral procedure","Distinct procedural service"], correctIndex: 0, rationale: "Modifier -53 reports a discontinued procedure. The physician elected to terminate the procedure due to risk to the patient's well-being.", difficulty: 2, category: "CPT/HCPCS Coding", topic: "CPT Modifiers" },
  { id: "him-209", stem: "What is the correct code for a new patient office visit with straightforward MDM?", options: ["99202","99201","99211","99212"], correctIndex: 0, rationale: "99202 is for new patient office visits with straightforward MDM. Note: 99201 was deleted effective 2021. 99211 is for established patients (nurse visits).", difficulty: 2, category: "CPT/HCPCS Coding", topic: "E/M Coding" },
  { id: "him-210", stem: "Conscious sedation provided by the same physician performing the procedure is coded using:", options: ["99151-99153 depending on patient age and time","99100","99140","No separate code — included in the procedure"], correctIndex: 0, rationale: "Moderate (conscious) sedation by the same physician is reported with 99151-99153. These codes are time-based and vary by patient age (under 5, 5+).", difficulty: 3, category: "CPT/HCPCS Coding", topic: "Sedation Coding" },
  { id: "him-211", stem: "Under HIPAA, which individual has the right to request restrictions on PHI use?", options: ["The patient (individual)","Only the attending physician","Only the insurance company","Only the hospital administrator"], correctIndex: 0, rationale: "Under HIPAA, patients have the right to request restrictions on uses and disclosures of their PHI. The covered entity does not have to agree except for self-pay disclosures to health plans.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Patient Rights" },
  { id: "him-212", stem: "A risk assessment under the HIPAA Security Rule must evaluate:", options: ["All potential threats and vulnerabilities to the confidentiality, integrity, and availability of ePHI","Only external hacking threats","Only employee compliance","Only firewall effectiveness"], correctIndex: 0, rationale: "A comprehensive risk assessment must evaluate ALL threats (natural, human, environmental), vulnerabilities (technical, administrative, physical), and their impact on ePHI.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Risk Assessment" },
  { id: "him-213", stem: "Multi-factor authentication (MFA) is an example of which type of HIPAA safeguard?", options: ["Technical safeguard (access control)","Administrative safeguard","Physical safeguard","Organizational safeguard"], correctIndex: 0, rationale: "MFA is a technical safeguard implementing access control. It requires two or more verification factors (knowledge, possession, inherence) before granting access to ePHI.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "Access Controls" },
  { id: "him-214", stem: "What is the purpose of clinical templates in an EHR?", options: ["Providing structured documentation guides for consistent and complete charting","Creating marketing materials","Managing financial reports","Scheduling maintenance"], correctIndex: 0, rationale: "Clinical templates provide structured frameworks for documenting patient encounters, ensuring consistency, completeness, and supporting coded data entry.", difficulty: 1, category: "EHR Systems & Health IT", topic: "EHR Documentation" },
  { id: "him-215", stem: "ICD-10-CM encoder software assists coders by:", options: ["Guiding code selection through look-up tools, cross-references, and coding guidelines","Automatically assigning codes without coder input","Replacing physician documentation","Generating patient bills directly"], correctIndex: 0, rationale: "Encoder software provides search, look-up, cross-references, inclusion/exclusion notes, and guideline prompts to assist coders in selecting the most accurate codes.", difficulty: 1, category: "EHR Systems & Health IT", topic: "Coding Technology" },
  { id: "him-216", stem: "What is computer-assisted coding (CAC)?", options: ["Technology that uses NLP and algorithms to suggest codes from clinical documentation","Manually looking up codes in a codebook","Coding done exclusively by computers without human review","Voice recognition software for dictation"], correctIndex: 0, rationale: "CAC uses NLP and algorithms to analyze clinical documentation and suggest appropriate diagnosis and procedure codes for coder review and validation.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Coding Technology" },
  { id: "him-217", stem: "What is a capitation payment model?", options: ["A fixed per-member-per-month payment regardless of services used","Payment based on each individual service","Payment only for emergency services","Payment based on patient satisfaction scores"], correctIndex: 0, rationale: "Capitation pays providers a fixed amount per enrolled member per month, regardless of services rendered. It shifts financial risk to the provider.", difficulty: 2, category: "Revenue Cycle Management", topic: "Payment Models" },
  { id: "him-218", stem: "The Medicare Severity DRG (MS-DRG) system uses which factors for grouping?", options: ["Principal diagnosis, secondary diagnoses (CC/MCC), procedures, age, sex, and discharge status","Only the principal diagnosis","Only procedures performed","Only length of stay"], correctIndex: 0, rationale: "MS-DRGs consider principal and secondary diagnoses, surgical procedures, age, sex, and discharge status. CCs and MCCs significantly impact DRG assignment and payment.", difficulty: 2, category: "Revenue Cycle Management", topic: "DRG System" },
  { id: "him-219", stem: "What does 'timely filing' refer to in healthcare billing?", options: ["The deadline by which claims must be submitted to a payer to be eligible for payment","Filing patient records in chronological order","Submitting employee timesheets","Filing tax returns for the healthcare organization"], correctIndex: 0, rationale: "Timely filing deadlines (varying by payer, typically 90-365 days from date of service) must be met or claims will be denied regardless of validity.", difficulty: 2, category: "Revenue Cycle Management", topic: "Claims Management" },
  { id: "him-220", stem: "What is an Explanation of Benefits (EOB)?", options: ["A statement from the insurer to the patient explaining what was covered, paid, and owed","A physician's explanation of treatment options","A hospital's benefit package for employees","A government regulation document"], correctIndex: 0, rationale: "An EOB is sent by the insurance company to the patient explaining what medical treatments/services were paid, adjusted, and what the patient owes.", difficulty: 1, category: "Revenue Cycle Management", topic: "Payment Processing" },
  { id: "him-221", stem: "What is the impact of accurate documentation on Hospital-Acquired Condition (HAC) reporting?", options: ["Proper POA documentation prevents misclassification of pre-existing conditions as hospital-acquired, affecting reimbursement","No impact on reporting","Only affects Joint Commission surveys","Only relevant for outpatient settings"], correctIndex: 0, rationale: "Accurate POA indicators distinguish pre-existing conditions from HACs. Incorrect classification can result in non-payment under CMS HAC Reduction Program.", difficulty: 3, category: "Clinical Documentation Improvement", topic: "HAC Reporting" },
  { id: "him-222", stem: "A CDI specialist reviews a patient with documented 'altered mental status.' What query might be appropriate?", options: ["Query for the underlying cause of altered mental status (e.g., encephalopathy, delirium, metabolic cause)","No query needed — altered mental status is sufficient","Query to remove the diagnosis","Query to add unrelated diagnoses"], correctIndex: 0, rationale: "'Altered mental status' is a symptom, not a definitive diagnosis. CDI should query for the underlying etiology (encephalopathy, delirium, metabolic disturbance) which carries CC/MCC weight.", difficulty: 3, category: "Clinical Documentation Improvement", topic: "CDI Queries" },
  { id: "him-223", stem: "What role does the CDI specialist play in quality measure accuracy?", options: ["Ensuring documentation supports accurate quality measure reporting and risk adjustment","No role in quality measures","Only reviewing billing codes","Only training new coders"], correctIndex: 0, rationale: "CDI impacts quality measures through accurate severity documentation, mortality indicators, readmission risk factors, and hospital-acquired conditions — all affecting CMS quality programs.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "Quality Impact" },
  { id: "him-224", stem: "What is prevalence in epidemiology?", options: ["The total number of existing cases of a disease at a specific point in time","The number of new cases per year","The death rate from a disease","The cure rate for a disease"], correctIndex: 0, rationale: "Prevalence measures the total number of existing cases (old and new) at a point in time or period. It differs from incidence, which measures only new cases.", difficulty: 2, category: "Data Analytics & Quality", topic: "Epidemiology" },
  { id: "him-225", stem: "Lean methodology in healthcare quality focuses on:", options: ["Eliminating waste and improving efficiency in processes","Adding more staff to every department","Increasing the number of procedures performed","Extending patient length of stay"], correctIndex: 0, rationale: "Lean methodology identifies and eliminates waste (overproduction, waiting, transportation, overprocessing, inventory, motion, defects) to improve process efficiency and value delivery.", difficulty: 2, category: "Data Analytics & Quality", topic: "Quality Methodologies" },
  { id: "him-226", stem: "Six Sigma in healthcare aims to:", options: ["Reduce process variation and defects to near-zero levels using DMAIC methodology","Increase process variation for flexibility","Eliminate all quality programs","Reduce staffing to six people"], correctIndex: 0, rationale: "Six Sigma uses DMAIC (Define, Measure, Analyze, Improve, Control) to reduce defects to 3.4 per million opportunities through rigorous data-driven process improvement.", difficulty: 2, category: "Data Analytics & Quality", topic: "Quality Methodologies" },
  { id: "him-227", stem: "What is the purpose of a compliance hotline?", options: ["Providing a confidential mechanism for employees to report suspected violations without fear of retaliation","A phone line for patient appointments","A technical support line for IT issues","A line for ordering supplies"], correctIndex: 0, rationale: "A compliance hotline allows anonymous/confidential reporting of suspected fraud, waste, abuse, or policy violations. Non-retaliation policies protect reporters.", difficulty: 1, category: "Compliance & Legal", topic: "Compliance Programs" },
  { id: "him-228", stem: "What is the penalty for unauthorized access to medical records under state laws?", options: ["Varies by state but may include fines, imprisonment, and loss of professional license","No penalties exist","Only a verbal warning","A $10 fine"], correctIndex: 0, rationale: "State penalties for unauthorized medical record access vary widely and may include criminal charges, fines ranging from hundreds to thousands of dollars, imprisonment, and loss of professional licensure.", difficulty: 2, category: "Compliance & Legal", topic: "State Regulations" },
  { id: "him-229", stem: "The Patient Safety and Quality Improvement Act of 2005 provides:", options: ["Federal legal privilege and confidentiality protections for information reported to Patient Safety Organizations (PSOs)","Immunity from all medical malpractice claims","Unlimited government funding for quality programs","Mandatory quality reporting for all providers"], correctIndex: 0, rationale: "The PSQ Act provides legal privilege and confidentiality for patient safety work product reported to PSOs, encouraging voluntary reporting and analysis of medical errors.", difficulty: 3, category: "Compliance & Legal", topic: "Patient Safety Legislation" },
  { id: "him-230", stem: "What are the benefits of medication history from an HIE for emergency departments?", options: ["Comprehensive medication list reduces duplicate prescriptions, adverse interactions, and improves treatment decisions","No significant benefits","Only benefits the pharmacy","Only useful for billing"], correctIndex: 0, rationale: "HIE medication history provides ED clinicians with a comprehensive list of current medications from multiple sources, reducing adverse drug interactions, duplications, and improving clinical decisions.", difficulty: 2, category: "Health Information Exchange", topic: "Clinical Benefits" },
  { id: "him-231", stem: "What is event notification in an HIE?", options: ["Automated alerts sent to subscribed providers when their patients have encounters at other facilities","Notification of system downtime","Billing event tracking","Staff scheduling notifications"], correctIndex: 0, rationale: "Event notification (ADT alerts) automatically notifies primary care providers, care managers, and health plans when their patients are admitted, discharged, or transferred at participating facilities.", difficulty: 2, category: "Health Information Exchange", topic: "Care Coordination" },
  { id: "him-232", stem: "Data use agreements (DUAs) in HIE contexts:", options: ["Define how shared health data may be used, stored, and disclosed by receiving organizations","Replace BAAs entirely","Are only needed for research","Apply only to government agencies"], correctIndex: 0, rationale: "DUAs establish terms for how shared data will be used, stored, protected, and eventually destroyed. They complement BAAs and address specific data sharing arrangements.", difficulty: 2, category: "Health Information Exchange", topic: "Data Governance" },
  { id: "him-233", stem: "What is the primary purpose of the UHDDS (Uniform Hospital Discharge Data Set)?", options: ["Standardizing the collection of hospital inpatient data for reporting and analysis","Standardizing outpatient billing","Creating hospital marketing reports","Tracking employee attendance"], correctIndex: 0, rationale: "UHDDS defines a minimum set of data elements collected at discharge for each inpatient stay including demographics, diagnoses, procedures, and disposition. It standardizes data for national health statistics.", difficulty: 2, category: "Data Analytics & Quality", topic: "Data Standards" },
  { id: "him-234", stem: "What is the purpose of abstracting in health information management?", options: ["Extracting specific data elements from medical records for databases and registries","Creating abstracts of medical journal articles","Summarizing meeting minutes","Generating patient bills"], correctIndex: 0, rationale: "Abstracting involves reviewing medical records and extracting key data points (diagnoses, procedures, dates, outcomes) into databases, registries, or reporting systems.", difficulty: 1, category: "Data Analytics & Quality", topic: "Data Collection" },
  { id: "him-235", stem: "What is release of information (ROI) in HIM?", options: ["The process of disclosing patient health information to authorized requestors following legal requirements","Releasing new software versions","Publishing research findings","Releasing staff schedules"], correctIndex: 0, rationale: "ROI is the controlled process of disclosing PHI in response to valid requests, ensuring compliance with HIPAA, state laws, and organizational policies.", difficulty: 1, category: "Compliance & Legal", topic: "Information Release" },
  { id: "him-236", stem: "What is the role of a health information management (HIM) director?", options: ["Overseeing all aspects of health information services including coding, ROI, data management, and compliance","Performing surgery","Prescribing medications","Managing the hospital cafeteria"], correctIndex: 0, rationale: "The HIM director manages the department responsible for medical records, coding, transcription, ROI, cancer registry, data analytics, and regulatory compliance.", difficulty: 1, category: "Compliance & Legal", topic: "HIM Leadership" },
  { id: "him-237", stem: "Cancer registry data collection follows standards set by:", options: ["Commission on Cancer (CoC) and state cancer registries","Individual hospital preferences","Insurance companies","Drug manufacturers"], correctIndex: 0, rationale: "Cancer registries follow standards from CoC/ACS, NAACCR, and state registries for collecting staging, treatment, and outcome data on cancer patients.", difficulty: 2, category: "Data Analytics & Quality", topic: "Cancer Registry" },
  { id: "him-238", stem: "What is the purpose of a mortality review committee?", options: ["Reviewing deaths that occur in the facility to identify potential quality issues and improvement opportunities","Assigning legal blame for deaths","Calculating mortality statistics only","Processing death certificates"], correctIndex: 0, rationale: "Mortality review committees examine deaths to identify potential care quality issues, system failures, and opportunities for improvement while maintaining peer review protections.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "Mortality Review" },
  { id: "him-239", stem: "The AHIMA Code of Ethics requires HIM professionals to:", options: ["Maintain the confidentiality and integrity of health information while advocating for data quality","Share patient data freely with any requestor","Prioritize revenue over accuracy","Modify records to benefit the facility"], correctIndex: 0, rationale: "AHIMA's ethical standards require HIM professionals to protect confidentiality, ensure data integrity, advocate for accurate documentation, and comply with laws and regulations.", difficulty: 1, category: "Compliance & Legal", topic: "Professional Ethics" },
  { id: "him-240", stem: "What is the difference between a discharge summary and a progress note?", options: ["A discharge summary is a comprehensive overview at discharge; progress notes document ongoing daily care","They are identical documents","Discharge summaries are for outpatients only","Progress notes are written after discharge"], correctIndex: 0, rationale: "A discharge summary provides a comprehensive overview of the entire hospital stay at discharge. Progress notes document the patient's daily course, assessments, and plans during the stay.", difficulty: 1, category: "Clinical Documentation Improvement", topic: "Documentation Types" },
  { id: "him-241", stem: "What is the Ambulatory Payment Classification (APC) system?", options: ["Medicare's outpatient prospective payment system grouping procedures for payment","An inpatient payment system","A physician payment system","A pharmaceutical pricing system"], correctIndex: 0, rationale: "APCs are Medicare's OPPS grouping mechanism for outpatient hospital services. Similar procedures are grouped into APCs with predetermined payment rates, similar to DRGs for inpatients.", difficulty: 2, category: "Revenue Cycle Management", topic: "Payment Systems" },
  { id: "him-242", stem: "What is the purpose of a case mix analysis?", options: ["Evaluating the types and complexity of patients treated to understand resource utilization and revenue impact","Mixing different patient cases together","Analyzing medical supply inventory","Creating patient meal plans"], correctIndex: 0, rationale: "Case mix analysis examines the distribution of patient types, severity levels, and resource consumption to inform budgeting, staffing, and strategic planning.", difficulty: 2, category: "Revenue Cycle Management", topic: "Financial Analysis" },
  { id: "him-243", stem: "What does the term 'data dictionary' mean in health information management?", options: ["A comprehensive reference defining data elements, their definitions, formats, and allowed values","A regular English dictionary","A medical terminology textbook","A database of patient names"], correctIndex: 0, rationale: "A data dictionary is a metadata repository describing each data element's name, definition, data type, format, source, allowed values, and business rules.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Data Management" },
  { id: "him-244", stem: "What is record reconciliation in HIM?", options: ["Ensuring all patient records are accounted for and complete before permanent filing","Balancing the department budget","Resolving disagreements between staff","Matching patient with correct physician"], correctIndex: 0, rationale: "Record reconciliation verifies that all discharged patient records are received, all required documents are present, and the record is complete before permanent storage.", difficulty: 1, category: "Data Analytics & Quality", topic: "Record Management" },
  { id: "him-245", stem: "What is the Health Information Technology for Economic and Clinical Health (HITECH) Act's impact on breach penalties?", options: ["Significantly increased HIPAA penalty amounts and added breach notification requirements","Reduced all HIPAA penalties","Eliminated breach reporting","Had no impact on penalties"], correctIndex: 0, rationale: "HITECH increased maximum annual HIPAA penalties to $1.5 million per violation category, added mandatory breach notification, and extended HIPAA requirements to business associates.", difficulty: 2, category: "HIPAA Privacy & Security", topic: "HITECH Act" },
  { id: "him-246", stem: "What is the Medicare Access and CHIP Reauthorization Act (MACRA)?", options: ["Legislation that replaced the Sustainable Growth Rate with the Quality Payment Program (MIPS and APMs)","A law about children's health insurance only","A regulation about hospital construction","A pharmaceutical pricing law"], correctIndex: 0, rationale: "MACRA replaced SGR with QPP, creating two payment tracks: Merit-based Incentive Payment System (MIPS) and Advanced Alternative Payment Models (APMs) to incentivize quality and value.", difficulty: 3, category: "Revenue Cycle Management", topic: "Payment Reform" },
  { id: "him-247", stem: "What is the purpose of a health record audit?", options: ["Systematically reviewing records for compliance with documentation standards, coding accuracy, and regulatory requirements","Auditing financial statements","Reviewing employee performance","Checking hospital building maintenance"], correctIndex: 0, rationale: "Health record audits systematically review documentation for completeness, accuracy, timeliness, compliance with regulations, and coding accuracy to identify improvement opportunities.", difficulty: 2, category: "Compliance & Legal", topic: "Auditing" },
  { id: "him-248", stem: "Prospective payment systems (PPS) pay providers based on:", options: ["Predetermined rates for defined services or episodes rather than actual costs","Actual costs incurred for each service","Patient-reported satisfaction scores","The number of employees in the facility"], correctIndex: 0, rationale: "PPS pays predetermined rates for defined services (DRGs for inpatient, APCs for outpatient) regardless of actual costs. This incentivizes efficiency.", difficulty: 2, category: "Revenue Cycle Management", topic: "Payment Systems" },
  { id: "him-249", stem: "The Joint Commission's 'Do Not Use' abbreviation list exists to:", options: ["Prevent medical errors caused by misinterpretation of dangerous abbreviations","Save space in medical records","Reduce typing time","Standardize marketing materials"], correctIndex: 0, rationale: "The 'Do Not Use' list identifies abbreviations prone to misinterpretation (e.g., U for units, IU for international units) that can cause medication errors and patient harm.", difficulty: 1, category: "Clinical Documentation Improvement", topic: "Documentation Standards" },
  { id: "him-250", stem: "What is the National Patient Safety Goals (NPSG) program?", options: ["Joint Commission requirements targeting specific areas of patient safety concern","National park safety guidelines","Patient exercise recommendations","Staff safety training programs"], correctIndex: 0, rationale: "NPSGs are annually updated Joint Commission requirements addressing specific patient safety priorities including patient identification, medication safety, infection prevention, and fall prevention.", difficulty: 2, category: "Compliance & Legal", topic: "Patient Safety" },
  { id: "him-251", stem: "What is clinical pathway variance in outcomes analysis?", options: ["A deviation from the expected course of treatment or outcomes defined in a clinical pathway","A change in hospital hallway layout","A variation in staff scheduling","A difference in hospital billing rates"], correctIndex: 0, rationale: "Variance analysis identifies deviations from clinical pathways (expected LOS, complications, readmissions) to improve care processes and outcomes.", difficulty: 3, category: "Data Analytics & Quality", topic: "Clinical Pathways" },
  { id: "him-252", stem: "Credential verification for medical staff includes checking:", options: ["Education, training, licensure, board certification, malpractice history, and references","Only the physician's resume","Only board certification","Only the state medical license"], correctIndex: 0, rationale: "Credentialing verifies education, residency training, current licensure, board certification, DEA registration, malpractice history, sanctions, and peer references.", difficulty: 2, category: "Compliance & Legal", topic: "Credentialing" },
  { id: "him-253", stem: "What is an enterprise master patient index (EMPI)?", options: ["An MPI that spans multiple facilities or systems within an integrated delivery network","A simple patient list for one clinic","A patient satisfaction survey","A list of referring physicians"], correctIndex: 0, rationale: "An EMPI links patient identities across all facilities and systems in a healthcare enterprise, ensuring unique patient identification for continuity of care and accurate data aggregation.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Patient Identification" },
  { id: "him-254", stem: "The Minimum Data Set (MDS) is used in:", options: ["Skilled nursing facilities for resident assessment and care planning","Acute care hospitals for discharge planning","Physician offices for documentation","Pharmacies for drug dispensing"], correctIndex: 0, rationale: "The MDS is a standardized assessment tool used in nursing facilities/SNFs as part of the federally mandated resident assessment process, driving care planning and PPS payment (RUG scores).", difficulty: 2, category: "Data Analytics & Quality", topic: "Long-Term Care" },
  { id: "him-255", stem: "What is the function of an institutional review board (IRB)?", options: ["Reviewing and approving research involving human subjects to ensure ethical standards are met","Reviewing hospital building construction","Approving new medical devices for sale","Setting insurance reimbursement rates"], correctIndex: 0, rationale: "IRBs review research protocols involving human subjects to ensure ethical standards (informed consent, risk-benefit analysis, privacy protections) are met before research begins.", difficulty: 2, category: "Compliance & Legal", topic: "Research Ethics" },
  { id: "him-256", stem: "What does the term 'data stewardship' mean in HIM?", options: ["The responsibility for managing data throughout its lifecycle to ensure quality, accessibility, and security","Storing data in a warehouse","Deleting old data","Printing data reports"], correctIndex: 0, rationale: "Data stewardship involves accountability for managing data assets including defining standards, ensuring quality, maintaining security, and supporting appropriate access throughout the data lifecycle.", difficulty: 2, category: "Data Analytics & Quality", topic: "Data Governance" },
  { id: "him-257", stem: "What is a covered entity under HIPAA?", options: ["A health plan, healthcare clearinghouse, or healthcare provider that transmits any health information electronically","Any business in the US","Only hospitals","Only insurance companies"], correctIndex: 0, rationale: "Covered entities are: health plans, healthcare clearinghouses, and healthcare providers who transmit any health information in electronic form in connection with HIPAA-standard transactions.", difficulty: 1, category: "HIPAA Privacy & Security", topic: "HIPAA Scope" },
  { id: "him-258", stem: "What is a hybrid record system?", options: ["A system using both paper and electronic formats for maintaining patient health information","A system for hybrid vehicles","A system combining two different EHR vendors","A combined inpatient/outpatient record"], correctIndex: 0, rationale: "Hybrid records use a combination of paper and electronic media for different parts of the health record. Managing the legal health record in a hybrid environment requires clear policies.", difficulty: 1, category: "EHR Systems & Health IT", topic: "Record Systems" },
  { id: "him-259", stem: "What is the purpose of version control in health IT?", options: ["Tracking changes to documents, code sets, and systems to maintain integrity and allow rollback","Controlling which version of a game employees play","Managing patient admission versions","Tracking vehicle models in parking lots"], correctIndex: 0, rationale: "Version control tracks modifications to clinical documents, databases, and software. It maintains change history, supports auditing, enables rollback, and ensures data integrity.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Data Integrity" },
  { id: "him-260", stem: "OASIS (Outcome and Assessment Information Set) is used by:", options: ["Home health agencies for patient assessment and quality measurement","Hospitals for inpatient assessment","Nursing homes for resident assessment","Physician offices for annual exams"], correctIndex: 0, rationale: "OASIS is the HHA-specific standardized assessment tool mandated by CMS for all adult patients receiving skilled care. It drives the Home Health PPS and quality reporting.", difficulty: 2, category: "Data Analytics & Quality", topic: "Home Health" },
  { id: "him-261", stem: "What is the legal health record (LHR)?", options: ["The subset of the entire patient record that the organization defines as its official record for legal and disclosure purposes","Every piece of data ever created about a patient","Only the discharge summary","Only physician notes"], correctIndex: 0, rationale: "The LHR is the organization-defined documentation that constitutes the business record disclosed upon request. It may not include all data in the EHR (e.g., metadata, audit trails).", difficulty: 2, category: "Compliance & Legal", topic: "Legal Health Record" },
  { id: "him-262", stem: "What is the difference between authentication and authorization in health IT security?", options: ["Authentication verifies identity; authorization determines what the authenticated user is permitted to access","They are the same thing","Authentication is for patients; authorization is for staff","Authentication is a physical process; authorization is digital"], correctIndex: 0, rationale: "Authentication confirms who the user is (passwords, biometrics, tokens). Authorization determines what that verified user is allowed to do (read, write, delete) based on their role.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Security Concepts" },
  { id: "him-263", stem: "Per diem payment means:", options: ["A fixed daily rate for inpatient services regardless of specific services rendered","Payment per procedure","Payment per diagnosis","Payment per hour of care"], correctIndex: 0, rationale: "Per diem (per day) payment provides a flat daily rate for inpatient care. The rate may vary by type of unit (medical, surgical, ICU) but is not based on specific services rendered that day.", difficulty: 2, category: "Revenue Cycle Management", topic: "Payment Models" },
  { id: "him-264", stem: "What is clinical coding?", options: ["The process of transforming clinical diagnoses, procedures, and services into standardized numeric or alphanumeric codes","Writing clinical research papers","Creating hospital newsletters","Designing clinical trials"], correctIndex: 0, rationale: "Clinical coding transforms documented diagnoses, procedures, and services into standard code sets (ICD-10-CM/PCS, CPT/HCPCS) for billing, reporting, and statistical analysis.", difficulty: 1, category: "ICD-10-CM/PCS Coding", topic: "Coding Fundamentals" },
  { id: "him-265", stem: "What is the function of a tumor registry?", options: ["Collecting, analyzing, and reporting data on cancer patients for treatment evaluation and epidemiological research","Registering patients for tumor removal surgery","A waiting list for oncology appointments","A pharmaceutical database for cancer drugs"], correctIndex: 0, rationale: "Tumor registries collect standardized data on cancer diagnoses, staging, treatment, and outcomes. They support quality improvement, research, and compliance with CoC standards.", difficulty: 2, category: "Data Analytics & Quality", topic: "Cancer Registry" },
  { id: "him-266", stem: "MS-DRG weight reflects:", options: ["The relative costliness of treating patients in that DRG compared to the average Medicare patient","The physical weight of the patient","The importance of the diagnosis","The number of physicians involved"], correctIndex: 0, rationale: "DRG weights are relative values reflecting average resource consumption. A weight of 1.0 = average. Higher weights (e.g., 3.5 for organ transplant) indicate more resource-intensive care.", difficulty: 2, category: "Revenue Cycle Management", topic: "DRG System" },
  { id: "him-267", stem: "What is the difference between a charge code and a CPT code?", options: ["Charge codes are facility-specific internal codes; CPT codes are standardized national codes for procedures","They are identical","Charge codes are used only by physicians","CPT codes are used only by hospitals"], correctIndex: 0, rationale: "Charge codes are internal facility identifiers in the chargemaster. CPT codes are nationally standardized procedure codes. The chargemaster maps internal charge codes to CPT/HCPCS for claims.", difficulty: 2, category: "Revenue Cycle Management", topic: "Chargemaster" },
  { id: "him-268", stem: "What is a grouper in the context of MS-DRGs?", options: ["Software that assigns claims to the appropriate DRG based on coded data elements","A person who groups patients by diagnosis","A type of medical device","A quality improvement team"], correctIndex: 0, rationale: "A DRG grouper is software that processes coded data (principal/secondary diagnoses, procedures, demographics) through decision trees to assign the appropriate MS-DRG.", difficulty: 2, category: "Revenue Cycle Management", topic: "DRG System" },
  { id: "him-269", stem: "What is the Outpatient Prospective Payment System (OPPS)?", options: ["Medicare payment system for hospital outpatient services using Ambulatory Payment Classifications","A system for inpatient payment","A physician payment system","A pharmacy reimbursement system"], correctIndex: 0, rationale: "OPPS uses APCs to classify outpatient services for Medicare reimbursement. Payment rates are based on the geometric mean cost of services within each APC.", difficulty: 2, category: "Revenue Cycle Management", topic: "Payment Systems" },
  { id: "him-270", stem: "What is the purpose of a Notice of Noncoverage (NOMNC)?", options: ["Informing a Medicare beneficiary that Medicare will no longer cover their services in a skilled nursing or home health setting","A notice about non-payment to physicians","A notice about hospital construction","A notice about staff termination"], correctIndex: 0, rationale: "The NOMNC informs Medicare beneficiaries of planned termination of Medicare coverage in SNF, HHA, or CORF settings, providing them the right to appeal the decision.", difficulty: 3, category: "Revenue Cycle Management", topic: "Medicare Coverage" },
  { id: "him-271", stem: "In healthcare data quality, what does 'timeliness' refer to?", options: ["Data is available when needed for clinical, administrative, or analytical purposes","Data is formatted correctly","Data is accurate","Data is stored securely"], correctIndex: 0, rationale: "Timeliness means data is current and available when needed. Delayed documentation or coding can impact care decisions, billing cycles, and quality reporting deadlines.", difficulty: 1, category: "Data Analytics & Quality", topic: "Data Quality Dimensions" },
  { id: "him-272", stem: "What is the primary difference between structured and unstructured data?", options: ["Structured data is organized in predefined formats; unstructured data is free-form text or media","Structured data is more important","Unstructured data is always inaccurate","There is no meaningful difference"], correctIndex: 0, rationale: "Structured data uses defined fields, codes, and formats enabling computation. Unstructured data includes free-text notes, images, and audio requiring NLP or manual review for analysis.", difficulty: 1, category: "Data Analytics & Quality", topic: "Data Types" },
  { id: "him-273", stem: "What is the purpose of a clinical pathway?", options: ["A standardized, evidence-based care plan that defines expected interventions and outcomes for a specific diagnosis","A physical path through the hospital","A career advancement plan for clinicians","A billing workflow document"], correctIndex: 0, rationale: "Clinical pathways outline day-by-day expected care activities, outcomes, and discharge criteria for specific conditions, reducing variation and improving quality.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "Clinical Pathways" },
  { id: "him-274", stem: "The Health Insurance Portability and Accountability Act was enacted in what year?", options: ["1996","2000","2003","2009"], correctIndex: 0, rationale: "HIPAA was enacted August 21, 1996. The Privacy Rule was finalized in 2000 (effective 2003) and the Security Rule in 2003 (effective 2005).", difficulty: 1, category: "HIPAA Privacy & Security", topic: "HIPAA History" },
  { id: "him-275", stem: "What is the role of a privacy officer under HIPAA?", options: ["Designated individual responsible for developing and implementing privacy policies and procedures","A law enforcement position","A clinical care provider","An IT system administrator"], correctIndex: 0, rationale: "HIPAA requires covered entities to designate a privacy officer responsible for privacy policies, workforce training, complaint handling, and ensuring compliance with the Privacy Rule.", difficulty: 1, category: "HIPAA Privacy & Security", topic: "HIPAA Administration" },
  { id: "him-276", stem: "What is a mapping table in health IT terminology management?", options: ["A crosswalk linking codes from one classification system to another for data translation","A table showing hospital floor plans","A directory of geographic locations","A list of patient addresses"], correctIndex: 0, rationale: "Mapping tables (crosswalks) translate codes between systems (e.g., ICD-9 to ICD-10, SNOMED to ICD-10) enabling data continuity and interoperability across different code sets.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Terminology Management" },
  { id: "him-277", stem: "Deficiency analysis in HIM involves:", options: ["Reviewing discharged patient records for missing or incomplete documentation","Analyzing building structural defects","Reviewing financial deficiencies","Analyzing staff performance issues"], correctIndex: 0, rationale: "Deficiency analysis identifies incomplete documentation (missing signatures, H&Ps, operative reports, discharge summaries) and tracks delinquent records for physician completion.", difficulty: 1, category: "Data Analytics & Quality", topic: "Record Completion" },
  { id: "him-278", stem: "What is the purpose of clinical documentation integrity (CDI) metrics dashboards?", options: ["Tracking CDI program performance including query rates, response rates, impact on CMI, and reviewer productivity","Monitoring patient vital signs","Tracking medication administration times","Scheduling staff meetings"], correctIndex: 0, rationale: "CDI dashboards visualize key metrics: query volume/response rates, CC/MCC capture rates, CMI impact, review coverage, and reviewer productivity for program management.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "CDI Metrics" },
  { id: "him-279", stem: "What is the correct way to code a principal diagnosis for a patient who was admitted for diagnostic workup that proved inconclusive?", options: ["Code the reason for the admission (sign, symptom, or condition that prompted evaluation)","Code the condition ruled out","Use an unspecified diagnosis code","Do not assign a principal diagnosis"], correctIndex: 0, rationale: "When a definitive diagnosis is not established, the principal diagnosis is the condition/symptom/sign that was the reason for admission and prompted the diagnostic workup.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Principal Diagnosis Selection" },
  { id: "him-280", stem: "The National Drug Code (NDC) identifies:", options: ["Specific drug products including manufacturer, product, and package size","Medical procedures","Diagnostic tests","Durable medical equipment"], correctIndex: 0, rationale: "The NDC is a 10-digit, 3-segment code identifying: labeler/manufacturer (first segment), product (second segment), and package size/type (third segment).", difficulty: 2, category: "CPT/HCPCS Coding", topic: "Drug Coding" },
  { id: "him-281", stem: "Severity-adjusted length of stay compares:", options: ["Actual LOS to the expected LOS for patients with similar severity levels to assess efficiency","All patients' LOS equally regardless of condition","Only surgical patients' LOS","LOS to the calendar year"], correctIndex: 0, rationale: "Severity-adjusted LOS controls for patient acuity when comparing efficiency. It compares actual LOS to expected LOS based on DRG, severity, and case mix to identify outliers.", difficulty: 3, category: "Data Analytics & Quality", topic: "Performance Metrics" },
  { id: "him-282", stem: "What is a comorbidity in coding?", options: ["A pre-existing condition that coexists with the principal diagnosis and affects treatment or length of stay","The principal diagnosis itself","A condition that develops after admission","A family history of disease"], correctIndex: 0, rationale: "A comorbidity is a pre-existing condition present on admission that affects treatment, LOS, or resource consumption. Complications develop after admission. Both impact DRG assignment as CCs/MCCs.", difficulty: 1, category: "ICD-10-CM/PCS Coding", topic: "Coding Definitions" },
  { id: "him-283", stem: "What is a complication in coding?", options: ["A condition that develops after admission that affects treatment or length of stay","A pre-existing condition","The principal diagnosis","A resolved condition from a previous admission"], correctIndex: 0, rationale: "A complication develops after admission and affects the patient's course of treatment or LOS. When appropriately documented and coded, complications may serve as CCs/MCCs.", difficulty: 1, category: "ICD-10-CM/PCS Coding", topic: "Coding Definitions" },
  { id: "him-284", stem: "The UB-04 form is used for:", options: ["Submitting institutional claims (hospital inpatient and outpatient)","Professional physician claims","Pharmacy claims","Workers' compensation claims only"], correctIndex: 0, rationale: "The UB-04 (CMS-1450) is the standard claim form for institutional providers (hospitals, SNFs, HHAs). The CMS-1500 is for professional claims.", difficulty: 1, category: "Revenue Cycle Management", topic: "Claims Submission" },
  { id: "him-285", stem: "A revenue code on the UB-04 identifies:", options: ["The department or type of service where the charge was incurred","The specific CPT procedure performed","The patient's diagnosis","The attending physician"], correctIndex: 0, rationale: "Revenue codes (3-4 digits) identify the department/type of service (e.g., 0120 = room and board, semi-private, 0250 = pharmacy) on institutional claims.", difficulty: 2, category: "Revenue Cycle Management", topic: "Claims Components" },
  { id: "him-286", stem: "What is clinical data abstraction?", options: ["Extracting specific clinical information from medical records for databases, registries, and quality reporting","Writing summaries of clinical research","Creating patient education materials","Abstracting art from clinical settings"], correctIndex: 0, rationale: "Clinical data abstraction involves systematically extracting defined data elements from medical records for purposes including quality reporting (CMS Core Measures), registries, and research.", difficulty: 1, category: "Data Analytics & Quality", topic: "Data Collection" },
  { id: "him-287", stem: "CMS Core Measures track quality for:", options: ["Specific clinical conditions to compare hospital performance and drive quality improvement","Administrative efficiency only","Financial performance","Employee satisfaction"], correctIndex: 0, rationale: "CMS Core Measures track evidence-based processes and outcomes for conditions like heart failure, pneumonia, and surgical care to assess and compare hospital quality performance.", difficulty: 2, category: "Data Analytics & Quality", topic: "Quality Reporting" },
  { id: "him-288", stem: "What is a clinical trial in the context of research?", options: ["A planned experiment testing medical treatments on human volunteers to evaluate safety and effectiveness","A legal proceeding against a physician","A test of hospital equipment","An employee training exercise"], correctIndex: 0, rationale: "Clinical trials are systematic studies testing interventions (drugs, devices, procedures) in human subjects through phases (I-IV) to establish safety and efficacy.", difficulty: 1, category: "Compliance & Legal", topic: "Clinical Research" },
  { id: "him-289", stem: "An Accountable Care Organization (ACO) is:", options: ["A group of providers who voluntarily share accountability for the quality and cost of care for a defined patient population","A single physician's practice","An insurance company","A pharmaceutical manufacturer"], correctIndex: 0, rationale: "ACOs are groups of providers sharing responsibility for quality and cost of care for assigned Medicare beneficiaries. They may share savings achieved below spending benchmarks.", difficulty: 2, category: "Revenue Cycle Management", topic: "Value-Based Care" },
  { id: "him-290", stem: "The AHIMA professional credential RHIT stands for:", options: ["Registered Health Information Technician","Registered Hospital Information Technologist","Recognized Health IT professional","Registered HIPAA Information Trainer"], correctIndex: 0, rationale: "RHIT = Registered Health Information Technician, awarded by AHIMA to graduates of CAHIIM-accredited associate degree HIM programs who pass the certification exam.", difficulty: 1, category: "Compliance & Legal", topic: "Professional Credentials" },
  { id: "him-291", stem: "The term 'medical necessity' in billing refers to:", options: ["Services that are reasonable and necessary for the diagnosis or treatment of the patient's condition","Any service a physician wants to perform","Services requested by the patient","The most expensive treatment option"], correctIndex: 0, rationale: "Medical necessity means services must be reasonable and necessary for diagnosis/treatment of illness or injury. Payers deny claims for services lacking documented medical necessity.", difficulty: 1, category: "Revenue Cycle Management", topic: "Medical Necessity" },
  { id: "him-292", stem: "What is a data set in healthcare?", options: ["A defined collection of data elements collected for a specific purpose","Any random group of numbers","A database backup file","A data storage device"], correctIndex: 0, rationale: "A data set is a structured collection of data elements (e.g., UHDDS for inpatient discharge data, OASIS for home health) collected systematically for specific reporting/analysis purposes.", difficulty: 1, category: "Data Analytics & Quality", topic: "Data Standards" },
  { id: "him-293", stem: "Relative Value Units (RVUs) in the Medicare Physician Fee Schedule consist of:", options: ["Work RVU, practice expense RVU, and malpractice RVU","Only work RVU","Revenue and cost RVUs","Patient satisfaction and quality RVUs"], correctIndex: 0, rationale: "Total RVU = work RVU (physician effort) + practice expense RVU (overhead) + malpractice RVU (liability insurance). Each is multiplied by a geographic adjustment factor and conversion factor.", difficulty: 2, category: "Revenue Cycle Management", topic: "Physician Payment" },
  { id: "him-294", stem: "The condition code on a UB-04 claim identifies:", options: ["Special conditions or events that affect claim processing","The patient's ICD-10 diagnosis code","The attending physician's specialty","The patient's insurance plan type"], correctIndex: 0, rationale: "Condition codes (form locator 18-28) identify special circumstances affecting claim processing, such as SNF qualifying stay, disability, workers' comp, or patient status conditions.", difficulty: 2, category: "Revenue Cycle Management", topic: "Claims Components" },
  { id: "him-295", stem: "An occurrence code on a UB-04 identifies:", options: ["A significant event date related to the billing of the claim","The occurrence of a specific diagnosis","How often a procedure was performed","The frequency of patient visits"], correctIndex: 0, rationale: "Occurrence codes identify dates of events that may affect claim payment, such as accident date, onset of symptoms, start of infertility treatment, or retirement date.", difficulty: 2, category: "Revenue Cycle Management", topic: "Claims Components" },
  { id: "him-296", stem: "What is the purpose of the discharge disposition on a claim?", options: ["Indicating where the patient went after leaving the hospital and their status at discharge","Describing the patient's mood at discharge","Documenting the physician's satisfaction with care","Recording the patient's final lab values"], correctIndex: 0, rationale: "Discharge disposition (status code) indicates the patient's destination (home, SNF, AMA, expired) and affects DRG payment, transfer policies, and post-acute care tracking.", difficulty: 1, category: "Revenue Cycle Management", topic: "Claims Components" },
  { id: "him-297", stem: "What is utilization review (UR)?", options: ["Evaluating the appropriateness and medical necessity of healthcare services and resources used","Reviewing employee utilization of break time","Auditing utility bills for the hospital","Reviewing patient satisfaction surveys"], correctIndex: 0, rationale: "UR evaluates whether services are medically necessary, appropriate, and provided in the right setting. It includes preadmission, concurrent, and retrospective review.", difficulty: 2, category: "Clinical Documentation Improvement", topic: "Utilization Management" },
  { id: "him-298", stem: "The geometric mean length of stay (GMLOS) for a DRG:", options: ["Represents the typical length of stay for cases within that DRG, calculated using the geometric mean","Is the longest possible stay for that DRG","Is the average of all hospital stays nationally","Applies only to outpatient cases"], correctIndex: 0, rationale: "GMLOS is calculated using the geometric mean (less influenced by extreme outliers than arithmetic mean) of stays within a DRG. It's used for DRG payment calculations.", difficulty: 3, category: "Revenue Cycle Management", topic: "DRG System" },
  { id: "him-299", stem: "What is an encoder in medical coding?", options: ["Software that automates the code assignment process by guiding coders through classification systems","A hardware device for scanning documents","A person who memorizes all codes","A system for encoding patient names"], correctIndex: 0, rationale: "Encoders are coding software tools that assist coders by providing searchable code databases, coding guidelines, edits, and cross-references for accurate code assignment.", difficulty: 1, category: "EHR Systems & Health IT", topic: "Coding Tools" },
  { id: "him-300", stem: "What does AHIMA stand for?", options: ["American Health Information Management Association","Allied Health Information Managers of America","Association of Healthcare Information and Management Administrators","American Hospital Information Management Alliance"], correctIndex: 0, rationale: "AHIMA (American Health Information Management Association) is the premier professional association for HIM professionals, offering credentials (RHIA, RHIT, CCS), education, and advocacy.", difficulty: 1, category: "Compliance & Legal", topic: "Professional Organizations" },
  { id: "him-301", stem: "What is a nosocomial infection?", options: ["An infection acquired during a hospital stay that was not present or incubating at admission","A community-acquired infection","A congenital infection","An infection from contaminated food"], correctIndex: 0, rationale: "Nosocomial (healthcare-associated) infections are acquired during healthcare delivery that were not present at admission. Common types include CAUTI, CLABSI, VAP, and SSI.", difficulty: 1, category: "Clinical Documentation Improvement", topic: "Healthcare-Associated Conditions" },
  { id: "him-302", stem: "What is a secondary data source?", options: ["Data derived from primary sources (medical records) that has been abstracted for specific purposes","The original medical record","Data entered directly by the patient","Real-time monitoring data"], correctIndex: 0, rationale: "Secondary data sources (registries, indexes, health databases) contain data extracted/abstracted from primary sources (medical records) for specific analytical, reporting, or research purposes.", difficulty: 2, category: "Data Analytics & Quality", topic: "Data Sources" },
  { id: "him-303", stem: "The International Classification of Diseases is maintained by:", options: ["World Health Organization (WHO)","American Medical Association (AMA)","Centers for Medicare and Medicaid Services (CMS)","National Institutes of Health (NIH)"], correctIndex: 0, rationale: "WHO maintains the ICD classification system. In the US, CMS and NCHS (CDC) maintain the clinical modification (ICD-10-CM) and CMS maintains the procedure coding system (ICD-10-PCS).", difficulty: 1, category: "ICD-10-CM/PCS Coding", topic: "Classification Systems" },
  { id: "him-304", stem: "What is a Transfer DRG?", options: ["A DRG where payment is adjusted when a patient is transferred to another acute care facility before the GMLOS","A DRG for patients transferred to a nursing home","A code used when transferring records between hospitals","A DRG for ambulance transfers"], correctIndex: 0, rationale: "Transfer DRGs apply per diem payment (per day) when patients are transferred to another acute care facility before completing the expected LOS, rather than the full DRG payment.", difficulty: 3, category: "Revenue Cycle Management", topic: "DRG System" },
  { id: "him-305", stem: "What is the function of a nomenclature in healthcare?", options: ["A systematic method of naming concepts, diseases, procedures using standard terminology","A list of hospital employee names","A register of medical device patents","A catalog of pharmaceutical products"], correctIndex: 0, rationale: "A nomenclature provides a systematic set of names (e.g., SNOMED CT) with defined relationships. Unlike classifications which group similar items, nomenclatures provide specific unique terms.", difficulty: 2, category: "EHR Systems & Health IT", topic: "Clinical Terminologies" },
  { id: "him-306", stem: "ICD-10-CM placeholder character 'x' is used when:", options: ["A code requires a specific number of characters but not all positions have applicable values","Indicating an unknown diagnosis","Marking confidential information","The code has been retired"], correctIndex: 0, rationale: "The placeholder 'x' fills empty positions so the required 7th character extension can be placed correctly. For example, T36.0x1A uses 'x' to fill the 5th character position.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Code Structure" },
  { id: "him-307", stem: "What is the purpose of a patient index in HIM?", options: ["A file/database containing patient identifiers used to locate medical records","An index of patient satisfaction scores","A list of patient allergies","A financial index of patient accounts"], correctIndex: 0, rationale: "The patient index (master patient index/MPI) contains identifying information used to locate, link, and retrieve patient health records across the organization.", difficulty: 1, category: "Data Analytics & Quality", topic: "Record Management" },
  { id: "him-308", stem: "What is a disease index?", options: ["A listing of diseases and conditions coded in the facility's records, searchable by ICD code","A book describing symptoms of all diseases","A patient satisfaction survey","A list of communicable diseases only"], correctIndex: 0, rationale: "The disease index lists all diagnoses coded in a facility's records, organized by ICD code, enabling retrieval for research, quality improvement, and statistical reporting.", difficulty: 1, category: "Data Analytics & Quality", topic: "Health Record Indexes" },
  { id: "him-309", stem: "What is the National Provider Identifier (NPI)?", options: ["A unique 10-digit identification number assigned to healthcare providers by CMS","A patient's Social Security number","A hospital's tax identification number","An insurance plan identifier"], correctIndex: 0, rationale: "The NPI is a unique, permanent 10-digit number assigned by CMS to all healthcare providers. Required on all HIPAA standard transactions including claims, eligibility inquiries, and remittances.", difficulty: 1, category: "Revenue Cycle Management", topic: "Provider Identification" },
  { id: "him-310", stem: "What is the significance of the principal procedure in DRG assignment?", options: ["The procedure most related to the principal diagnosis that is performed for definitive treatment rather than diagnosis","The first procedure performed chronologically","The most expensive procedure","The longest procedure"], correctIndex: 0, rationale: "The principal procedure is defined as the procedure performed for definitive treatment most related to the principal diagnosis. It affects DRG assignment and surgical vs. medical classification.", difficulty: 2, category: "ICD-10-CM/PCS Coding", topic: "Procedure Coding" },
];
